// Processing screen — simple, clean stepped loader
const Processing = ({ onComplete }) => {
  const [progress, setProgress] = React.useState(0);

  const agents = [
    { id: "research", title: "Researching companies", desc: "Pulling firmographics, recent news, hiring signals", icon: "globe" },
    { id: "contacts", title: "Finding decision-makers", desc: "Apollo lookup · 142 of 150 found", icon: "user" },
    { id: "writer",   title: "Drafting personalized emails", desc: "GPT-5 · using your template + per-contact context", icon: "edit" },
    { id: "verify",   title: "Verifying deliverability", desc: "MX records, syntax, role-account flags", icon: "check" },
  ];

  React.useEffect(() => {
    const t = setInterval(() => setProgress((p) => Math.min(100, p + 1.5)), 80);
    return () => clearInterval(t);
  }, []);

  const stepIdx = Math.min(agents.length - 1, Math.floor(progress / 25));

  return (
    <div className="shell">
      <Sidebar active="new" />
      <div className="main">
        <Topbar
          crumb={
            <>
              <span className="muted">New campaign</span>
              <Icon name="chev_r" size={11} className="sep" style={{ color: "var(--fg-3)" }} />
              <span>B2B sales outreach</span>
              <span className="badge b-ready" style={{ marginLeft: 8 }}><span className="badge-dot" />Processing</span>
            </>
          }
          right={<button className="btn btn-sm">Run in background</button>}
        />
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 32, gap: 24, overflow: "auto" }}>
          <div style={{ width: "100%", maxWidth: 560 }}>
            <div style={{ textAlign: "center", marginBottom: 28 }}>
              <div style={{ fontSize: 11, fontWeight: 500, letterSpacing: 0.06 + "em", textTransform: "uppercase", color: "var(--accent)", marginBottom: 10 }}>
                <span style={{ display: "inline-block", width: 6, height: 6, borderRadius: "50%", background: "var(--accent)", marginRight: 6, animation: "pulse 1.4s infinite" }} />
                Building your campaign
              </div>
              <h2 style={{ fontSize: 24, fontWeight: 600, letterSpacing: -0.01 + "em", margin: 0 }}>{Math.round(progress)}% complete</h2>
              <p style={{ fontSize: 13, color: "var(--fg-2)", marginTop: 8 }}>~{Math.max(1, Math.ceil((100 - progress) / 30))} min remaining · You can leave this page</p>
            </div>

            <div style={{ height: 4, background: "var(--bg-2)", borderRadius: 2, overflow: "hidden", marginBottom: 24 }}>
              <div style={{ height: "100%", background: "var(--accent)", width: `${progress}%`, transition: "width .3s" }} />
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {agents.map((a, i) => {
                const done = i < stepIdx;
                const active = i === stepIdx;
                return (
                  <div key={a.id} style={{ display: "flex", gap: 12, padding: 12, background: active ? "var(--bg-1)" : "transparent", border: "0.5px solid", borderColor: active ? "var(--accent)" : "var(--border)", borderRadius: 8, alignItems: "center" }}>
                    <div style={{ width: 28, height: 28, borderRadius: 7, background: done ? "var(--accent-dim)" : active ? "var(--bg-2)" : "var(--bg-1)", border: "0.5px solid", borderColor: done ? "var(--accent)" : "var(--border)", display: "grid", placeItems: "center", color: done ? "var(--accent)" : active ? "var(--fg)" : "var(--fg-3)", flexShrink: 0 }}>
                      {done ? <Icon name="check" size={14} stroke={2.4} /> : active ? <span className="spinner" /> : <Icon name={a.icon} size={13} />}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 12.5, fontWeight: 500, color: done || active ? "var(--fg)" : "var(--fg-2)" }}>{a.title}</div>
                      <div style={{ fontSize: 11.5, color: "var(--fg-3)", marginTop: 2 }}>{a.desc}</div>
                    </div>
                    {done && <span style={{ fontSize: 10.5, color: "var(--fg-3)", fontFamily: "var(--font-mono)" }}>{(8 + i * 6).toFixed(1)}s</span>}
                  </div>
                );
              })}
            </div>

            <div style={{ display: "flex", justifyContent: "center", marginTop: 20 }}>
              <button className="btn btn-ghost btn-sm" onClick={onComplete}>Skip to dashboard →</button>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes pulse { 0%, 100% { opacity: 1 } 50% { opacity: .3 } }
        .spinner { width: 12px; height: 12px; border: 1.5px solid var(--border-strong); border-top-color: var(--accent); border-radius: 50%; animation: spin .8s linear infinite }
        @keyframes spin { to { transform: rotate(360deg) } }
      `}</style>
    </div>
  );
};

