const Sidebar = ({ active = "dashboard", counts = {} }) => {
  const items = [
    { id: "new", label: "New campaign", icon: "sparkles", accent: true },
  ];
  const camps = [
    { id: "dashboard", label: "Acme Q2 outbound", icon: "target", count: counts.dashboard },
    { id: "designers", label: "Design leads · NYC", icon: "target", count: 84 },
    { id: "ent-saas", label: "Enterprise SaaS", icon: "target", count: 42 },
  ];
  const lower = [
    { id: "drafts", label: "Drafts", icon: "file", count: 3 },
    { id: "archive", label: "Archive", icon: "folder" },
    { id: "settings", label: "Settings", icon: "settings" },
  ];
  return (
    <div className="sidebar">
      <div className="sb-brand">
        <div className="sb-brand-mark">O</div>
        <div>Outreach</div>
        <Icon name="chev_d" size={12} style={{ marginLeft: "auto", color: "var(--fg-3)" }} />
      </div>
      {items.map((it) => (
        <div key={it.id} className={`sb-item ${active === it.id ? "active" : ""}`} style={it.accent ? { color: "var(--accent)" } : null}>
          <Icon name={it.icon} size={14} style={it.accent ? { color: "var(--accent)" } : null} className="sb-icon" />
          <span>{it.label}</span>
          <span style={{ marginLeft: "auto", fontSize: 10.5, color: "var(--fg-3)", fontFamily: "var(--font-mono)" }}>⌘N</span>
        </div>
      ))}
      <div className="sb-section">Campaigns</div>
      {camps.map((it) => (
        <div key={it.id} className={`sb-item ${active === it.id ? "active" : ""}`}>
          <Icon name={it.icon} size={14} className="sb-icon" />
          <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{it.label}</span>
          {it.count != null && <span className="sb-count">{it.count}</span>}
        </div>
      ))}
      <div style={{ flex: 1 }} />
      {lower.map((it) => (
        <div key={it.id} className={`sb-item ${active === it.id ? "active" : ""}`}>
          <Icon name={it.icon} size={14} className="sb-icon" />
          <span>{it.label}</span>
          {it.count != null && <span className="sb-count">{it.count}</span>}
        </div>
      ))}
      <div className="sb-item" style={{ marginTop: 4 }}>
        <div style={{ width: 18, height: 18, borderRadius: "50%", background: "linear-gradient(135deg,#7dd3a0,#7aa7e8)", display: "grid", placeItems: "center", fontSize: 9.5, fontWeight: 600, color: "var(--accent-fg)" }}>JM</div>
        <span style={{ fontSize: 12 }}>Jordan M.</span>
        <Icon name="chev_d" size={12} style={{ marginLeft: "auto", color: "var(--fg-3)" }} />
      </div>
    </div>
  );
};

const Topbar = ({ crumb, right }) => (
  <div className="topbar">
    <div className="crumb">{crumb}</div>
    <div style={{ flex: 1 }} />
    {right}
  </div>
);

Object.assign(window, { Icon, Sidebar, Topbar });

