}

.mono {
  font-family: var(--font-mono);
  font-feature-settings: normal;
}

/* ---------- Buttons ---------- */
.btn {
  appearance: none;
  border: 0.5px solid var(--border-strong);
  background: var(--bg-2);
  color: var(--fg);
  font: inherit;
  font-weight: 500;
  font-size: 12.5px;
  height: 28px;
  padding: 0 11px;
  border-radius: var(--r-sm);
  display: inline-flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  transition: background 0.12s, border-color 0.12s;
  white-space: nowrap;
}
.btn:hover {
  background: var(--bg-3);
  border-color: #353c45;
}
.btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 1px;
}
.btn-primary {
  background: var(--accent);
  color: var(--accent-fg);
  border-color: transparent;
}
.btn-primary:hover {
  background: #92dcae;
}
.btn-ghost {
  background: transparent;
  border-color: transparent;
  color: var(--fg-2);
}
.btn-ghost:hover {
  background: var(--bg-2);
  color: var(--fg);
}
.btn-sm {
  height: 24px;
  font-size: 11.5px;
  padding: 0 8px;
}
.btn-icon {
  width: 28px;
  padding: 0;
  justify-content: center;
}
.btn-icon.btn-sm {
  width: 24px;
}

/* ---------- Form fields ---------- */
.field {
  appearance: none;
  width: 100%;
  background: var(--bg-1);
  border: 0.5px solid var(--border-strong);
  border-radius: var(--r-md);
  color: var(--fg);
  font: inherit;
  font-size: 13px;
  padding: 8px 11px;
  transition: border-color 0.12s, background 0.12s;
}
.field:focus {
  outline: none;
  border-color: var(--accent);
  background: var(--bg-2);
}
.field::placeholder {
  color: var(--fg-3);
}
textarea.field {
  resize: vertical;
  min-height: 80px;
  line-height: 1.55;
}

.label {
  display: block;
  font-size: 12px;
  font-weight: 500;
  color: var(--fg-1);
  margin-bottom: 6px;
}
.hint {
  font-size: 11.5px;
  color: var(--fg-2);
  margin-top: 6px;
  line-height: 1.45;
}

/* ---------- Badges ---------- */
.badge {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 20px;
  padding: 0 7px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.01em;
  background: var(--bg-3);
  color: var(--fg-1);
  border: 0.5px solid var(--border);
  white-space: nowrap;
}
.badge-dot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: currentColor;
  flex-shrink: 0;
}
.badge.b-draft {
  color: var(--fg-2);
}
.badge.b-ready {
  color: var(--blue);
  background: #7aa7e814;
}
.badge.b-sent {
  color: var(--accent);
  background: var(--accent-dim);
}
.badge.b-opened {
  color: var(--purple);
  background: #b8a1e814;
}
.badge.b-replied {
  color: var(--teal);
  background: #7ad3c914;
}
.badge.b-bounced {
  color: var(--red);
  background: #e87a7a14;
}

/* dot-only variant */
.badge.style-dot {
  background: transparent !important;
  border-color: transparent;
  padding: 0 4px;
  color: var(--fg-1) !important;
}
.badge.style-dot .badge-dot {
  background: currentColor;
}
.badge.style-dot.b-draft .badge-dot { background: var(--fg-3); }
.badge.style-dot.b-ready .badge-dot { background: var(--blue); }
.badge.style-dot.b-sent .badge-dot { background: var(--accent); }
.badge.style-dot.b-opened .badge-dot { background: var(--purple); }
.badge.style-dot.b-replied .badge-dot { background: var(--teal); }
.badge.style-dot.b-bounced .badge-dot { background: var(--red); }

/* minimal — just the label, no chrome */
.badge.style-minimal {
  background: transparent !important;
  border: 0;
  padding: 0;
  height: auto;
  font-weight: 500;
}
.badge.style-minimal .badge-dot { display: none; }

/* ---------- Generic surfaces ---------- */
.surface {
  background: var(--bg-1);
  border: 0.5px solid var(--border);
  border-radius: var(--r-lg);
}
.divider {
  height: 1px;
  background: var(--border);
  width: 100%;
}

/* ---------- Scrollbars ---------- */
.app *::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}
.app *::-webkit-scrollbar-track {
  background: transparent;
}
.app *::-webkit-scrollbar-thumb {
  background: #232a32;
  border: 2px solid transparent;
  background-clip: content-box;
  border-radius: 5px;
}
.app *::-webkit-scrollbar-thumb:hover {
  background: #2d3640;
  border: 2px solid transparent;
  background-clip: content-box;
}

/* ---------- Sidebar ---------- */
.sidebar {
  width: 220px;
  flex-shrink: 0;
  background: var(--bg);
  border-right: 0.5px solid var(--border);
  display: flex;
  flex-direction: column;
  padding: 10px 8px;
  gap: 2px;
}
.sb-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 8px 12px;
  font-weight: 600;
  font-size: 13.5px;
  letter-spacing: -0.01em;
}
.sb-brand-mark {
  width: 18px;
  height: 18px;
  border-radius: 5px;
  background: var(--accent);
  color: var(--accent-fg);
  display: grid;
  place-items: center;
  font-weight: 700;
  font-size: 11px;
  font-family: var(--font-mono);
}
.sb-section {
  font-size: 10.5px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--fg-3);
  padding: 12px 10px 4px;
}
.sb-item {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 5px 9px;
  border-radius: var(--r-sm);
  color: var(--fg-1);
  font-size: 12.5px;
  font-weight: 450;
  cursor: pointer;
  transition: background 0.1s;
}
.sb-item:hover {
  background: var(--bg-2);
}
.sb-item.active {
  background: var(--bg-3);
  color: var(--fg);
}
.sb-item .sb-icon {
  width: 14px;
  height: 14px;
  color: var(--fg-2);
  flex-shrink: 0;
}
.sb-item.active .sb-icon {
  color: var(--accent);
}
.sb-count {
  margin-left: auto;
  font-size: 10.5px;
  color: var(--fg-3);
  font-variant-numeric: tabular-nums;
}

/* ---------- Topbar ---------- */
.topbar {
  height: 44px;
  border-bottom: 0.5px solid var(--border);
  display: flex;
  align-items: center;
  padding: 0 14px;
  gap: 10px;
  flex-shrink: 0;
  background: var(--bg);
}
.crumb {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 12.5px;
  color: var(--fg-1);
}
.crumb .sep {
  color: var(--fg-3);
}
.crumb .muted {
  color: var(--fg-2);
}

/* ---------- Layout shells ---------- */
.shell {
  display: flex;
  height: 100%;
  width: 100%;
  background: var(--bg);
}
.main {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
}

