@keyframes cbDrift3 { 0% { transform: translate(0,0) scale(1) } 100% { transform: translate(80px, -60px) scale(1.2) } }
@keyframes cbDrift4 { 0% { transform: translate(-50%,-50%) scale(1) } 100% { transform: translate(-30%,-70%) scale(1.1) } }

