.auth-aurora .cb-blob-1 { width: 500px; height: 500px; top: 0; left: -10%; }
.auth-aurora .cb-blob-2 { width: 400px; height: 400px; top: 40%; right: -10%; }
.auth-aurora .cb-blob-3 { width: 300px; height: 300px; bottom: 0; left: 30%; }

