@import "tailwindcss";

:root {
  --bg: #0b0d0f;
  --bg-1: #0f1216;
  --bg-2: #14181d;
  --bg-3: #1a1f25;
  --border: #1f242a;
  --border-strong: #2a3038;
  --fg: #e8e8e8;
  --fg-1: #c9ccd1;
  --fg-2: #7a8290;
  --fg-3: #454c56;
  --accent: #7dd3a0;
  --accent-dim: #7dd3a022;
  --accent-fg: #0b0d0f;
  --blue: #7aa7e8;
  --amber: #e8b87a;
  --red: #e87a7a;
  --purple: #b8a1e8;
  --teal: #7ad3c9;
  --font-ui: "Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, "SF Mono", Menlo, monospace;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html, body {
  background: var(--bg);
  color: var(--fg);
  font-family: var(--font-ui);
  height: 100%;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

input, textarea, button, select {
  font-family: inherit;
}

@keyframes aurora-1 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(30px, -20px) scale(1.1); }
  66% { transform: translate(-20px, 10px) scale(0.9); }
}

@keyframes aurora-2 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(-40px, 20px) scale(1.15); }
  66% { transform: translate(20px, -30px) scale(0.85); }
}

@keyframes aurora-3 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  50% { transform: translate(20px, 30px) scale(1.2); }
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.fade-in {
  animation: fadeIn 0.3s ease forwards;
}

.aurora-blob-1 {
  animation: aurora-1 8s ease-in-out infinite;
}

.aurora-blob-2 {
  animation: aurora-2 10s ease-in-out infinite;
}

.aurora-blob-3 {
  animation: aurora-3 12s ease-in-out infinite;
}

