"use client";

import React from "react";
import { Icon } from "@/components/ui/Icon";
import { useRouter, useParams } from "next/navigation";

interface CampaignType {
  id: string;
  title: string;
  desc: string;
  tags: string[];
  icon: string;
  hot?: boolean;
}

export default function NewCampaignPage() {
  const router = useRouter();
  const params = useParams();
  const [input, setInput] = React.useState("");
  const [stage, setStage] = React.useState<"idle" | "picking">("idle");

  const types: CampaignType[] = [
    { id: "b2b", title: "B2B sales outreach", desc: "Find decision-makers at target companies and pitch them.", tags: ["Companies", "Personas", "Value prop"], icon: "building", hot: true },
    { id: "job", title: "Job outreach", desc: "Reach hiring managers with a tailored note + resume.", tags: ["Companies", "Roles", "Resume"], icon: "target" },
    { id: "fund", title: "Investor outreach", desc: "Warm intros to VCs and angels matching your stage.", tags: ["Stage", "Thesis", "Deck"], icon: "diamond" },
    { id: "custom", title: "Custom campaign", desc: "Define your own objective, audience, and message.", tags: ["Free-form"], icon: "sparkles" },
  ];

  const suggestions = [
    "Outreach to VP Engineering at Series B fintechs in NYC",
    "Recruit senior product designers at AI startups",
    "Pitch our analytics product to RevOps leaders",
  ];

  const handleSubmit = (val?: string) => {
    const text = val ?? input;
    if (!text.trim()) return;
    setInput(text);
    setStage("picking");
  };

  const onLaunch = async (typeId: string) => {
    try {
      const response = await fetch('/api/v1/campaigns', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type: typeId }),
      });
      const data = await response.json();
      router.push('/campaign/' + data.campaign_id + '/wizard');
    } catch (error) {
      console.error("Failed to launch campaign:", error);
    }
  };

  const onSignIn = () => {
    router.push('/auth');
  };

  return (
    <div className="chatbot" style={{ height: "100%", width: "100%", background: "var(--bg)", color: "var(--fg)", display: "flex", flexDirection: "column", position: "relative", overflow: "hidden" }}>
      {/* Animated gradient field */}
      <div className="cb-aurora" aria-hidden="true">
        <div className="cb-blob cb-blob-1" />
        <div className="cb-blob cb-blob-2" />
        <div className="cb-blob cb-blob-3" />
        <div className="cb-blob cb-blob-4" />
      </div>
      <div className="cb-grain" aria-hidden="true" />
      <div className="cb-grid" aria-hidden="true" />

      {/* Nav (unchanged) */}
      <div className="topbar" style={{ background: "transparent", borderColor: "transparent", position: "relative", zIndex: 3 }}>
        <div className="sb-brand" style={{ padding: 0 }}>
          <div className="sb-brand-mark">O</div>
          <div>Outreach</div>
        </div>
        <div style={{ flex: 1 }} />
        <button className="btn btn-ghost btn-sm">Docs</button>
        <button className="btn btn-sm" onClick={() => onSignIn()}>
          <Icon name="user" size={12} />Sign in
        </button>
      </div>

      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "72px 24px 48px", position: "relative", zIndex: 2, overflow: "auto" }}>
        <div style={{ maxWidth: 760, width: "100%", textAlign: "center" }}>
          <div className="cb-pill">
            <span className="cb-pill-dot" />
            <span>New · Apollo + GPT-5 routing</span>
            <span style={{ width: 1, height: 10, background: "rgba(255,255,255,0.12)" }} />
            <span style={{ color: "var(--accent)" }}>See changelog →</span>
          </div>

          <h1 className="cb-headline">
            <span className="cb-line">What campaign would you</span>
            <span className="cb-line">
              <span>like to </span>
              <span className="cb-shimmer">launch</span>
              <span> today?</span>
            </span>
          </h1>

          <p style={{ fontSize: 15.5, color: "var(--fg-2)", marginTop: 18, marginBottom: 32, lineHeight: 1.55, maxWidth: 560, marginLeft: "auto", marginRight: "auto" }}>
            Describe your audience and objective. We'll find the right people, draft personalized emails, and build you a sendable list — usually in under 4 minutes.
          </p>

          {/* Composer */}
          <div className="cb-composer">
            <div className="cb-composer-glow" aria-hidden="true" />
            <textarea
              className="field"
              placeholder="e.g. Reach VP Engineering at 100 mid-market fintechs about our observability tool…"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handleSubmit(); }}
              style={{ background: "transparent", border: 0, padding: "16px 16px 8px", minHeight: 92, fontSize: 14.5, lineHeight: 1.55, position: "relative", zIndex: 1 }}
            />
            <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "6px 8px 8px", position: "relative", zIndex: 1 }}>
              <button className="btn btn-ghost btn-sm" title="Attach"><Icon name="paperclip" size={13} /></button>
              <button className="btn btn-ghost btn-sm" title="Voice"><Icon name="mic" size={13} /></button>
              <div style={{ width: 1, height: 14, background: "var(--border)" }} />
              <div className="btn btn-ghost btn-sm" style={{ cursor: "default", color: "var(--fg-2)" }}>
                <Icon name="zap" size={12} />Auto-route
              </div>
              <div style={{ flex: 1 }} />
