"use client";

import React, { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";

interface ProcessingPageProps {
  params: Promise<{ id: string }>;
}

interface ProgressEvent {
  type: string;
  step?: string;
  message?: string;
  progress?: number;
  contact?: { company: string; person_name: string; title: string };
  count?: number;
  total_contacts?: number;
  total_drafts?: number;
}

const AGENT_STEPS = [
  { id: "research", label: "Contact Research", icon: "🔍", desc: "Finding matching contacts" },
  { id: "verify", label: "Email Verification", icon: "✉️", desc: "Verifying email addresses" },
  { id: "drafting", label: "Email Drafting", icon: "✍️", desc: "Generating personalized emails" },
  { id: "complete", label: "Quality Review", icon: "✅", desc: "Final review and cleanup" },
];

export default function ProcessingPage({ params }: ProcessingPageProps) {
  const { id } = use(params);
  const router = useRouter();
  const [progress, setProgress] = useState(0);
  const [currentStep, setCurrentStep] = useState("research");
  const [messages, setMessages] = useState<string[]>([]);
  const [done, setDone] = useState(false);
  const [contacts, setContacts] = useState<Array<{ company: string; person_name: string; title: string }>>([]);

  useEffect(() => {
    const evtSource = new EventSource(`/api/v1/campaigns/${id}/stream`);

    evtSource.onmessage = (e) => {
      try {
        const event: ProgressEvent = JSON.parse(e.data);

        if (event.type === "progress") {
          setProgress(event.progress || 0);
          setCurrentStep(event.step || "research");
          if (event.message) {
            setMessages((m) => [...m.slice(-8), event.message!]);
          }
        } else if (event.type === "contact_found" && event.contact) {
          setContacts((c) => [...c.slice(-5), event.contact!]);
        } else if (event.type === "complete") {
          setProgress(100);
          setDone(true);
          evtSource.close();
        }
      } catch {
        // ignore parse errors
      }
    };

    evtSource.onerror = () => {
      evtSource.close();
      setDone(true);
    };

    return () => evtSource.close();
  }, [id]);

  const activeStepIndex = AGENT_STEPS.findIndex((s) => s.id === currentStep);

  return (
    <div
      style={{
        height: "100vh",
        background: "var(--bg)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Aurora blobs */}
      <div
        className="aurora-blob-1"
        style={{
          position: "absolute",
          width: "500px",
          height: "500px",
          top: "-50px",
          left: "-50px",
          background: "radial-gradient(circle, #7dd3a028 0%, transparent 70%)",
          filter: "blur(70px)",
          borderRadius: "50%",
          pointerEvents: "none",
        }}
      />

      <div style={{ position: "relative", zIndex: 1, width: "100%", maxWidth: "560px", padding: "0 24px" }}>
        {/* Header */}
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          {!done ? (
            <>
              <div
                style={{
                  width: "48px",
                  height: "48px",
                  margin: "0 auto 16px",
                  border: "3px solid var(--border-strong)",
                  borderTopColor: "var(--accent)",
                  borderRadius: "50%",
                  animation: "spin-slow 0.9s linear infinite",
                }}
              />
              <h1 style={{ fontSize: "22px", fontWeight: 700, color: "var(--fg)", marginBottom: "8px" }}>
                Building your campaign
              </h1>
              <p style={{ fontSize: "14px", color: "var(--fg-2)" }}>
                Our AI agents are researching contacts and crafting personalized emails
              </p>
            </>
          ) : (
            <>
              <div
                style={{
                  width: "48px",
                  height: "48px",
                  margin: "0 auto 16px",
                  background: "var(--accent-dim)",
                  borderRadius: "50%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "24px",
                }}
              >
                ✓
              </div>
              <h1 style={{ fontSize: "22px", fontWeight: 700, color: "var(--fg)", marginBottom: "8px" }}>
                Campaign ready!
              </h1>
              <p style={{ fontSize: "14px", color: "var(--fg-2)" }}>
                Your emails are drafted and waiting for review
              </p>
            </>
          )}
        </div>

        {/* Progress bar */}
        <div
          style={{
            height: "4px",
            background: "var(--bg-3)",
            borderRadius: "2px",
            overflow: "hidden",
            marginBottom: "32px",
          }}
        >
          <div
            style={{
              height: "100%",
              background: "var(--accent)",
              borderRadius: "2px",
              width: `${progress}%`,
              transition: "width 0.5s ease",
            }}
          />
        </div>

        {/* Agent steps */}
        <div style={{ display: "flex", flexDirection: "column", gap: "8px", marginBottom: "24px" }}>
          {AGENT_STEPS.map((s, i) => {
            const isCurrent = s.id === currentStep && !done;
            const isPast = i < activeStepIndex || done;
            return (
              <div
                key={s.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "14px",
                  padding: "12px 16px",
                  background: isCurrent ? "var(--bg-2)" : "transparent",
                  border: `1px solid ${isCurrent ? "var(--border-strong)" : "transparent"}`,
                  borderRadius: "10px",
                  transition: "all 0.3s",
                }}
              >
                <div style={{ fontSize: "20px", opacity: isPast || isCurrent ? 1 : 0.3 }}>
                  {isPast && !isCurrent ? "✅" : s.icon}
                </div>
                <div style={{ flex: 1 }}>
                  <div
                    style={{
                      fontSize: "13px",
                      fontWeight: isCurrent ? 600 : 500,
                      color: isCurrent ? "var(--fg)" : isPast ? "var(--fg-1)" : "var(--fg-3)",
                    }}
                  >
                    {s.label}
                  </div>
                  <div style={{ fontSize: "11px", color: "var(--fg-3)", marginTop: "2px" }}>{s.desc}</div>
                </div>
                {isCurrent && (
                  <div
                    style={{
                      width: "8px",
                      height: "8px",
                      background: "var(--accent)",
                      borderRadius: "50%",
                      animation: "pulse-dot 1.2s ease-in-out infinite",
                    }}
                  />
                )}
              </div>
            );
          })}
        </div>

        {/* Live feed */}
        {contacts.length > 0 && (
          <div
            style={{
              background: "var(--bg-2)",
              border: "1px solid var(--border)",
              borderRadius: "10px",
              padding: "12px",
              marginBottom: "16px",
            }}
          >
            <div style={{ fontSize: "11px", color: "var(--fg-3)", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.06em" }}>
              Recent Contacts Found
            </div>
            {contacts.slice(-3).map((c, i) => (
              <div key={i} style={{ display: "flex", gap: "8px", padding: "4px 0", borderBottom: i < 2 ? "1px solid var(--border)" : "none" }}>
                <span style={{ fontSize: "12px", color: "var(--accent)", fontWeight: 500 }}>{c.company}</span>
                <span style={{ fontSize: "12px", color: "var(--fg-2)" }}>{c.person_name}</span>
                <span style={{ fontSize: "12px", color: "var(--fg-3)" }}>— {c.title}</span>
              </div>
            ))}
          </div>
        )}

        {/* Messages */}
        {messages.length > 0 && (
          <div
            style={{
              fontSize: "12px",
              color: "var(--fg-3)",
              textAlign: "center",
              marginBottom: "16px",
            }}
          >
            {messages[messages.length - 1]}
          </div>
        )}

        {/* Actions */}
        <div style={{ display: "flex", flexDirection: "column", gap: "8px", alignItems: "center" }}>
          {done && (
            <Button
              variant="primary"
              size="lg"
              onClick={() => router.push(`/campaign/${id}/dashboard`)}
              style={{ width: "100%", justifyContent: "center" }}
            >
              View Campaign →
            </Button>
          )}
          <button
            onClick={() => router.push(`/campaign/${id}/dashboard`)}
            style={{
              background: "none",
              border: "none",
              color: "var(--fg-3)",
              fontSize: "12px",
              cursor: "pointer",
              fontFamily: "var(--font-ui)",
            }}
          >
            Skip to dashboard
          </button>
        </div>
      </div>
    </div>
  );
}

input.content:
"use client";

import React from "react";
import { useParams, useRouter } from "next/navigation";
import { Icon } from "@/components/ui/Icon";
import { Sidebar } from "@/components/layout/Sidebar";
import { Topbar } from "@/components/layout/Topbar";

interface WizardData {
  intent: string;
  body: string;
  companies: string;
  regions: string[];
  titles: string[];
  companySize: string;
  industry: string;
  valueProp: string;
  sender: string;
  linkedin: string;
  emailSource: string;
  scrapingAck: boolean;
  llm: string;
}

const Field = ({ label, hint, children, optional }: { label: string; hint?: string; children: React.ReactNode; optional?: boolean }) => (
  <div style={{ marginBottom: 18 }}>
    <div className="label" style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
      <span>{label}</span>
      {optional && <span style={{ fontSize: 10.5, color: "var(--fg-3)", fontWeight: 400 }}>Optional</span>}
    </div>
    {children}
    {hint && <div className="hint">{hint}</div>}
  </div>
);

const Chip = ({ label, removable, onRemove }: { label: string; removable?: boolean; onRemove?: () => void }) => (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 4, padding: "3px 6px 3px 8px", background: "var(--bg-2)", border: "0.5px solid var(--border-strong)", borderRadius: 4, fontSize: 11.5, color: "var(--fg-1)" }}>
    {label}
    {removable && <button onClick={onRemove} style={{ background: "transparent", border: 0, color: "var(--fg-3)", cursor: "pointer", padding: 0, display: "grid", placeItems: "center" }}><Icon name="x" size={10} /></button>}
  </span>
);

const StepIntent = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "What are you pitching?" : "What roles are you looking for?"} hint="A sentence or two. We'll use this to personalize each email.">
      <textarea className="field" rows={3} value={data.intent} onChange={(e) => set("intent", e.target.value)} />
    </Field>
    {isB2B && (
      <Field label="One-line value proposition" hint="Used in subject lines and openers.">
        <input className="field" value={data.valueProp} onChange={(e) => set("valueProp", e.target.value)} />
      </Field>
    )}
    <Field label="Email body template" hint="Use {{firstName}}, {{company}}, {{role}} as variables. AI will personalize each line.">
      <textarea className="field" rows={7} value={data.body} onChange={(e) => set("body", e.target.value)} style={{ fontFamily: "var(--font-mono)", fontSize: 12.5 }} />
    </Field>
    <div style={{ display: "flex", gap: 8, alignItems: "center", padding: 10, background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 8 }}>
      <Icon name="sparkles" size={13} style={{ color: "var(--accent)" }} />
      <span style={{ fontSize: 12, color: "var(--fg-1)" }}>Want help writing? </span>
      <button className="btn btn-sm" style={{ marginLeft: "auto" }}>Generate template</button>
    </div>
  </>
);

const StepTarget = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "Target companies" : "Dream companies"} hint="Comma-separated. We'll also expand to similar companies if you'd like.">
      <textarea className="field" rows={3} value={data.companies} onChange={(e) => set("companies", e.target.value)} />
    </Field>
    {isB2B && (
      <>
        <Field label="Decision-maker titles">
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, padding: 8, background: "var(--bg-1)", border: "0.5px solid var(--border-strong)", borderRadius: 7, minHeight: 38 }}>
            {data.titles.map((t) => (
              <Chip key={t} label={t} removable onRemove={() => set("titles", (data.titles as string[]).filter((x) => x !== t))} />
            ))}
            <input placeholder="Add title…" style={{ flex: 1, minWidth: 100, background: "transparent", border: 0, color: "var(--fg)", fontSize: 12, padding: "2px 4px", outline: "none" }} />
          </div>
        </Field>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Field label="Industry">
            <input className="field" value={data.industry} onChange={(e) => set("industry", e.target.value)} />
          </Field>
          <Field label="Company size">
            <select className="field" value={data.companySize} onChange={(e) => set("companySize", e.target.value)}>
              <option value="1-50">1–50 employees</option>
              <option value="50-200">50–200 employees</option>
              <option value="100-1000">100–1,000 employees</option>
              <option value="1000+">1,000+ employees</option>
            </select>
          </Field>
        </div>
      </>
    )}
    <Field label="Regions">
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
        {["North America", "Europe", "LATAM", "APAC", "Remote"].map((r) => {
          const on = (data.regions as string[]).includes(r);
          return (
            <button key={r} onClick={() => set("regions", on ? (data.regions as string[]).filter((x) => x !== r) : [...(data.regions as string[]), r])} className="btn btn-sm" style={{ background: on ? "var(--accent-dim)" : "var(--bg-1)", borderColor: on ? "var(--accent)" : "var(--border-strong)", color: on ? "var(--accent)" : "var(--fg-1)" }}>
              {on && <Icon name="check" size={11} />}{r}
            </button>
          );
        })}
      </div>
    </Field>
  </>
);

const StepProfile = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label="Send from" hint="Emails will appear to come from this address.">
      <input className="field" value={data.sender} onChange={(e) => set("sender", e.target.value)} />
    </Field>
    <Field label="LinkedIn URL" hint="Used to enrich your sender bio in opening lines.">
      <div style={{ position: "relative" }}>
        <Icon name="link" size={13} style={{ position: "absolute", left: 11, top: 11, color: "var(--fg-3)" }} />
        <input className="field" value={data.linkedin} onChange={(e) => set("linkedin", e.target.value)} style={{ paddingLeft: 32 }} />
      </div>
    </Field>
    {!isB2B && (
      <Field label="Resume" hint="PDF or Drive link. Attached to outgoing emails.">
        <div style={{ display: "flex", gap: 8, padding: 12, background: "var(--bg-1)", border: "0.5px dashed var(--border-strong)", borderRadius: 7, alignItems: "center" }}>
          <Icon name="file" size={16} style={{ color: "var(--fg-2)" }} />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 12.5 }}>jordan-marsh-resume.pdf</div>
            <div style={{ fontSize: 11, color: "var(--fg-3)" }}>342 KB · Uploaded just now</div>
          </div>
          <button className="btn btn-sm">Replace</button>
        </div>
      </Field>
    )}
    <Field label="Portfolio / website" optional>
      <input className="field" placeholder="https://…" />
    </Field>
    <Field label="Calendar link" optional hint="We'll insert this in CTAs automatically.">
      <input className="field" placeholder="https://cal.com/jordan/15min" />
    </Field>
  </>
);

const StepSettings = ({ data, set }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void }) => (
  <>
    <div style={{ fontSize: 11, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 10 }}>Email sourcing</div>
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 12 }}>
      {[
        { id: "apollo", title: "Apollo API", desc: "Verified, deliverable emails. ~92% accuracy.", icon: "check", tag: "Recommended", tagClass: "b-sent" },
        { id: "scrape", title: "Web scraping", desc: "Free. Pulled from public sources.", icon: "warn", tag: "Higher bounce risk", tagClass: "b-bounced" },
      ].map((opt) => {
        const on = data.emailSource === opt.id;
        return (
          <div key={opt.id} onClick={() => set("emailSource", opt.id)} style={{ background: on ? "var(--bg-2)" : "var(--bg-1)", border: "1px solid", borderColor: on ? "var(--accent)" : "var(--border-strong)", borderRadius: 8, padding: 14, cursor: "pointer", position: "relative" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ width: 14, height: 14, borderRadius: "50%", border: "1.5px solid", borderColor: on ? "var(--accent)" : "var(--border-strong)", display: "grid", placeItems: "center" }}>
                {on && <div style={{ width: 6, height: 6, borderRadius: "50%", background: "var(--accent)" }} />}
              </div>
              <div style={{ fontSize: 13, fontWeight: 550 }}>{opt.title}</div>
            </div>
            <div style={{ fontSize: 11.5, color: "var(--fg-2)", marginTop: 8, lineHeight: 1.45 }}>{opt.desc}</div>
            <span className={`badge ${opt.tagClass}`} style={{ marginTop: 10 }}>
              <span className="badge-dot" />{opt.tag}
            </span>
          </div>
        );
      })}
    </div>

    {data.emailSource === "scrape" && (
      <div style={{ background: "rgba(232,184,122,0.08)", border: "0.5px solid rgba(232,184,122,0.3)", borderRadius: 8, padding: 14, marginBottom: 18, display: "flex", gap: 10 }}>
        <Icon name="warn" size={16} style={{ color: "var(--amber)", flexShrink: 0, marginTop: 1 }} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12.5, fontWeight: 550, color: "var(--amber)" }}>Heads up — emails sourced via scraping may be outdated</div>
          <div style={{ fontSize: 12, color: "var(--fg-1)", marginTop: 6, lineHeight: 1.55 }}>
            Scraped emails can be incorrect, role-based, or no longer monitored. Expect a bounce rate around 18–25% — significantly higher than Apollo. Repeated bounces can also affect your sender reputation.
          </div>
          <label style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 12, cursor: "pointer", fontSize: 12 }}>
            <input type="checkbox" checked={data.scrapingAck} onChange={(e) => set("scrapingAck", e.target.checked)} style={{ accentColor: "var(--amber)" }} />
            <span>I understand the risks and want to proceed with web scraping.</span>
          </label>
        </div>
      </div>
    )}

    <div style={{ fontSize: 11, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 10, marginTop: 8 }}>AI provider</div>
    <Field label="Model" hint="Used for personalization, subject lines, and reply drafting.">
      <select className="field" value={data.llm} onChange={(e) => set("llm", e.target.value)}>
        <option value="gpt-5">OpenAI · GPT-5 (recommended)</option>
        <option value="claude">Anthropic · Claude Sonnet 4.5</option>
        <option value="local">Local · Llama 3.3 70B</option>
      </select>
    </Field>
    <Field label="Tone" hint="How should drafts sound?">
      <div style={{ display: "flex", gap: 6 }}>
        {["Direct", "Warm", "Formal", "Casual"].map((t, i) => (
          <button key={t} className="btn btn-sm" style={{ background: i === 0 ? "var(--accent-dim)" : "var(--bg-1)", borderColor: i === 0 ? "var(--accent)" : "var(--border-strong)", color: i === 0 ? "var(--accent)" : "var(--fg-1)", flex: 1, justifyContent: "center" }}>{t}</button>
        ))}
      </div>
    </Field>
  </>
);

const StepReview = ({ data, isB2B, setStep }: { data: WizardData; isB2B: boolean; setStep: (n: number) => void }) => {
  const rows = [
    { label: "Campaign type", value: isB2B ? "B2B sales outreach" : "Job outreach", step: 0 },
    { label: "Intent", value: data.intent, step: 0, multi: true },
    { label: "Companies", value: data.companies.split(",").length + " companies", step: 1 },
    { label: "Titles", value: (data.titles as string[]).join(", "), step: 1 },
    { label: "Regions", value: (data.regions as string[]).join(", "), step: 1 },
    { label: "Sender", value: data.sender, step: 2 },
    { label: "Email source", value: data.emailSource === "apollo" ? "Apollo API" : "Web scraping", step: 3, warn: data.emailSource === "scrape" },
    { label: "AI model", value: ({ "gpt-5": "OpenAI GPT-5", claude: "Claude Sonnet 4.5", local: "Llama 3.3 70B" } as Record<string, string>)[data.llm], step: 3 },
  ];
  return (
    <>
      <div style={{ background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 10, overflow: "hidden", marginBottom: 18 }}>
        {rows.map((r, i) => (
          <div key={i} style={{ display: "flex", padding: "10px 14px", borderBottom: i < rows.length - 1 ? "0.5px solid var(--border)" : "none", gap: 12, alignItems: r.multi ? "flex-start" : "center" }}>
            <div style={{ width: 130, fontSize: 11.5, color: "var(--fg-2)", flexShrink: 0 }}>{r.label}</div>
            <div style={{ flex: 1, fontSize: 12.5, color: r.warn ? "var(--amber)" : "var(--fg)", lineHeight: 1.5, display: "flex", alignItems: "center", gap: 6 }}>
              {r.warn && <Icon name="warn" size={12} />}{r.value}
            </div>
            <button className="btn btn-ghost btn-sm" onClick={() => setStep(r.step)}>
              <Icon name="edit" size={11} />Edit
            </button>
          </div>
        ))}
      </div>
      <div style={{ background: "var(--bg-1)", border: "0.5px solid var(--accent)", borderRadius: 10, padding: 14, display: "flex", gap: 10, alignItems: "flex-start" }}>
        <Icon name="sparkles" size={15} style={{ color: "var(--accent)", marginTop: 2 }} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12.5, fontWeight: 550 }}>Ready to launch</div>
          <div style={{ fontSize: 12, color: "var(--fg-2)", marginTop: 4, lineHeight: 1.55 }}>
            We'll find ~150 contacts, draft personalized emails for each, and assemble your sendable list. Estimated time: <span style={{ color: "var(--fg)", fontFamily: "var(--font-mono)" }}>3–5 min</span>.
          </div>
        </div>
      </div>
    </>
  );
};

export default function WizardPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const [campaignType] = React.useState("b2b");
  const [step, setStep] = React.useState(0);
  const [data, setData] = React.useState<WizardData>({
    intent: "Pitch our observability platform to engineering leaders at Series B+ fintechs. Focus on teams suffering from MTTR pain.",
    body: "Hi {{firstName}},\n\nNoticed {{company}} just shipped real-time payments — congrats. Teams at that scale usually start hitting MTTR walls around 90 days in. We help engineering orgs cut MTTR by ~40% without ripping out their existing stack.\n\nWorth a 15-min look next week?\n\n— Jordan",
    companies: "Mercury, Ramp, Brex, Modern Treasury, Stripe Issuing, Plaid, Unit, Increase, Highnote, Lithic",
    regions: ["North America", "Europe"],
    titles: ["VP Engineering", "Head of Platform", "Director of Infrastructure"],
    companySize: "100-1000",
    industry: "Fintech / Payments",
    valueProp: "Cut MTTR by 40% with zero-instrumentation observability.",
    sender: "jordan@company.com",
    linkedin: "https://linkedin.com/in/jordan-marsh",
    emailSource: "apollo",
    scrapingAck: false,
    llm: "gpt-5",
  });

  const set = (k: keyof WizardData, v: unknown) => setData((d) => ({ ...d, [k]: v }));

  const isB2B = campaignType !== "job";
  const steps = isB2B
    ? [
        { id: "intent", title: "Intent", subtitle: "Why are you reaching out?" },
        { id: "target", title: "Target", subtitle: "Who should we contact?" },
        { id: "profile", title: "Sender", subtitle: "Who's sending these?" },
        { id: "settings", title: "Sources", subtitle: "Email + AI providers" },
        { id: "review", title: "Review", subtitle: "Confirm and launch" },
      ]
    : [
        { id: "intent", title: "Role", subtitle: "What are you looking for?" },
        { id: "target", title: "Targets", subtitle: "Where do you want to work?" },
        { id: "profile", title: "Profile", subtitle: "Resume + links" },
        { id: "settings", title: "Sources", subtitle: "Email + AI providers" },
        { id: "review", title: "Review", subtitle: "Confirm and launch" },
      ];

  const total = steps.length;
  const next = () => setStep((s) => Math.min(total - 1, s + 1));
  const prev = () => (step === 0 ? router.back() : setStep((s) => s - 1));

  const canAdvance = () => {
    if (step === 3 && data.emailSource === "scrape" && !data.scrapingAck) return false;
    return true;
  };

  const handleLaunch = async () => {
    await fetch(`/api/v1/campaigns/${id}/sessions`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ extracted_params: data }),
    });
    router.push(`/campaign/${id}/processing`);
  };

  return (
    <div className="shell">
      <Sidebar active="new" />
      <div className="main">
        <Topbar
          crumb={
            <>
              <span className="muted">New campaign</span>
              <Icon name="chev_r" size={11} className="sep" style={{ color: "var(--fg-3)" }} />
              <span>{isB2B ? "B2B sales outreach" : "Job outreach"}</span>
              <span className="badge b-draft" style={{ marginLeft: 8 }}>
                <span className="badge-dot" />Draft
              </span>
            </>
          }
          right={
            <>
              <span style={{ fontSize: 11, color: "var(--fg-3)" }}>Auto-saved 2s ago</span>
              <button className="btn btn-ghost btn-sm">Save and exit</button>
            </>
          }
        />

        <div style={{ display: "flex", flex: 1, minHeight: 0 }}>
          {/* Step rail */}
          <div style={{ width: 220, borderRight: "0.5px solid var(--border)", padding: 18, flexShrink: 0 }}>
            <div style={{ fontSize: 10.5, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 14 }}>Setup · {step + 1}/{total}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              {steps.map((s, i) => {
                const done = i < step;
                const active = i === step;
                return (
                  <div key={s.id} onClick={() => i <= step && setStep(i)} style={{ display: "flex", gap: 10, padding: "8px 8px", borderRadius: 6, background: active ? "var(--bg-2)" : "transparent", cursor: i <= step ? "pointer" : "default", alignItems: "flex-start" }}>
                    <div style={{ width: 18, height: 18, borderRadius: "50%", background: done ? "var(--accent)" : active ? "var(--bg-3)" : "var(--bg-2)", border: active ? "1px solid var(--accent)" : "0.5px solid var(--border-strong)", display: "grid", placeItems: "center", flexShrink: 0, marginTop: 1 }}>
                      {done ? <Icon name="check" size={11} stroke={2.4} style={{ color: "var(--accent-fg)" }} /> : <span style={{ fontSize: 10, fontWeight: 600, color: active ? "var(--accent)" : "var(--fg-3)", fontFamily: "var(--font-mono)" }}>{i + 1}</span>}
                    </div>
                    <div style={{ minWidth: 0 }}>
                      <div style={{ fontSize: 12.5, fontWeight: 500, color: active ? "var(--fg)" : done ? "var(--fg-1)" : "var(--fg-2)" }}>{s.title}</div>
                      <div style={{ fontSize: 11, color: "var(--fg-3)", marginTop: 1 }}>{s.subtitle}</div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div style={{ marginTop: 20, padding: 12, background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 8 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, color: "var(--fg-2)" }}>
                <Icon name="info" size={12} />Tip
              </div>
              <div style={{ fontSize: 11.5, color: "var(--fg-2)", marginTop: 6, lineHeight: 1.5 }}>
                You can paste raw notes anywhere. We'll extract structured fields from them automatically.
              </div>
            </div>
          </div>

          {/* Step content */}
          <div style={{ flex: 1, overflow: "auto", padding: "32px 48px 120px", position: "relative" }}>
            <div style={{ maxWidth: 640, margin: "0 auto" }}>
              <div style={{ fontSize: 10.5, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)" }}>Step {step + 1} of {total}</div>
              <h2 style={{ fontSize: 22, fontWeight: 600, letterSpacing: "-0.01em", margin: "6px 0 4px" }}>{steps[step].title}</h2>
              <p style={{ fontSize: 13.5, color: "var(--fg-2)", margin: "0 0 24px" }}>{steps[step].subtitle}</p>

              {step === 0 && <StepIntent data={data} set={set} isB2B={isB2B} />}
              {step === 1 && <StepTarget data={data} set={set} isB2B={isB2B} />}
              {step === 2 && <StepProfile data={data} set={set} isB2B={isB2B} />}
              {step === 3 && <StepSettings data={data} set={set} />}
              {step === 4 && <StepReview data={data} isB2B={isB2B} setStep={setStep} />}
            </div>
          </div>
        </div>

        {/* Footer nav */}
        <div style={{ height: 56, borderTop: "0.5px solid var(--border)", display: "flex", alignItems: "center", padding: "0 24px", flexShrink: 0, gap: 10, background: "var(--bg)" }}>
          <button className="btn btn-sm" onClick={prev}>
            <Icon name="arrow_l" size={12} />
            {step === 0 ? "Cancel" : "Back"}
          </button>
          <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 4 }}>
            {steps.map((_, i) => (
              <div key={i} style={{ width: 22, height: 3, borderRadius: 2, background: i <= step ? "var(--accent)" : "var(--bg-3)" }} />
            ))}
          </div>
          {step < total - 1 ? (
            <button className="btn btn-primary btn-sm" onClick={next} disabled={!canAdvance()} style={{ opacity: canAdvance() ? 1 : 0.5 }}>
              Continue
              <Icon name="arrow_r" size={12} />
            </button>
          ) : (
            <button className="btn btn-primary btn-sm" onClick={handleLaunch}>
              <Icon name="sparkles" size={12} />
              Launch campaign
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

toolUseResult.content:
"use client";

import React from "react";
import { useParams, useRouter } from "next/navigation";
import { Icon } from "@/components/ui/Icon";
import { Sidebar } from "@/components/layout/Sidebar";
import { Topbar } from "@/components/layout/Topbar";

interface WizardData {
  intent: string;
  body: string;
  companies: string;
  regions: string[];
  titles: string[];
  companySize: string;
  industry: string;
  valueProp: string;
  sender: string;
  linkedin: string;
  emailSource: string;
  scrapingAck: boolean;
  llm: string;
}

const Field = ({ label, hint, children, optional }: { label: string; hint?: string; children: React.ReactNode; optional?: boolean }) => (
  <div style={{ marginBottom: 18 }}>
    <div className="label" style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
      <span>{label}</span>
      {optional && <span style={{ fontSize: 10.5, color: "var(--fg-3)", fontWeight: 400 }}>Optional</span>}
    </div>
    {children}
    {hint && <div className="hint">{hint}</div>}
  </div>
);

const Chip = ({ label, removable, onRemove }: { label: string; removable?: boolean; onRemove?: () => void }) => (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 4, padding: "3px 6px 3px 8px", background: "var(--bg-2)", border: "0.5px solid var(--border-strong)", borderRadius: 4, fontSize: 11.5, color: "var(--fg-1)" }}>
    {label}
    {removable && <button onClick={onRemove} style={{ background: "transparent", border: 0, color: "var(--fg-3)", cursor: "pointer", padding: 0, display: "grid", placeItems: "center" }}><Icon name="x" size={10} /></button>}
  </span>
);

const StepIntent = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "What are you pitching?" : "What roles are you looking for?"} hint="A sentence or two. We'll use this to personalize each email.">
      <textarea className="field" rows={3} value={data.intent} onChange={(e) => set("intent", e.target.value)} />
    </Field>
    {isB2B && (
      <Field label="One-line value proposition" hint="Used in subject lines and openers.">
        <input className="field" value={data.valueProp} onChange={(e) => set("valueProp", e.target.value)} />
      </Field>
    )}
    <Field label="Email body template" hint="Use {{firstName}}, {{company}}, {{role}} as variables. AI will personalize each line.">
      <textarea className="field" rows={7} value={data.body} onChange={(e) => set("body", e.target.value)} style={{ fontFamily: "var(--font-mono)", fontSize: 12.5 }} />
    </Field>
    <div style={{ display: "flex", gap: 8, alignItems: "center", padding: 10, background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 8 }}>
      <Icon name="sparkles" size={13} style={{ color: "var(--accent)" }} />
      <span style={{ fontSize: 12, color: "var(--fg-1)" }}>Want help writing? </span>
      <button className="btn btn-sm" style={{ marginLeft: "auto" }}>Generate template</button>
    </div>
  </>
);

const StepTarget = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "Target companies" : "Dream companies"} hint="Comma-separated. We'll also expand to similar companies if you'd like.">
      <textarea className="field" rows={3} value={data.companies} onChange={(e) => set("companies", e.target.value)} />
    </Field>
    {isB2B && (
      <>
        <Field label="Decision-maker titles">
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, padding: 8, background: "var(--bg-1)", border: "0.5px solid var(--border-strong)", borderRadius: 7, minHeight: 38 }}>
            {data.titles.map((t) => (
              <Chip key={t} label={t} removable onRemove={() => set("titles", (data.titles as string[]).filter((x) => x !== t))} />
            ))}
            <input placeholder="Add title…" style={{ flex: 1, minWidth: 100, background: "transparent", border: 0, color: "var(--fg)", fontSize: 12, padding: "2px 4px", outline: "none" }} />
          </div>
        </Field>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Field label="Industry">
            <input className="field" value={data.industry} onChange={(e) => set("industry", e.target.value)} />
          </Field>
          <Field label="Company size">
            <select className="field" value={data.companySize} onChange={(e) => set("companySize", e.target.value)}>
              <option value="1-50">1–50 employees</option>
              <option value="50-200">50–200 employees</option>
              <option value="100-1000">100–1,000 employees</option>
              <option value="1000+">1,000+ employees</option>
            </select>
          </Field>
        </div>
      </>
    )}
    <Field label="Regions">
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
        {["North America", "Europe", "LATAM", "APAC", "Remote"].map((r) => {
          const on = (data.regions as string[]).includes(r);
          return (
            <button key={r} onClick={() => set("regions", on ? (data.regions as string[]).filter((x) => x !== r) : [...(data.regions as string[]), r])} className="btn btn-sm" style={{ background: on ? "var(--accent-dim)" : "var(--bg-1)", borderColor: on ? "var(--accent)" : "var(--border-strong)", color: on ? "var(--accent)" : "var(--fg-1)" }}>
              {on && <Icon name="check" size={11} />}{r}
            </button>
          );
        })}
      </div>
    </Field>
  </>
);

const StepProfile = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label="Send from" hint="Emails will appear to come from this address.">
      <input className="field" value={data.sender} onChange={(e) => set("sender", e.target.value)} />
    </Field>
    <Field label="LinkedIn URL" hint="Used to enrich your sender bio in opening lines.">
      <div style={{ position: "relative" }}>
        <Icon name="link" size={13} style={{ position: "absolute", left: 11, top: 11, color: "var(--fg-3)" }} />
        <input className="field" value={data.linkedin} onChange={(e) => set("linkedin", e.target.value)} style={{ paddingLeft: 32 }} />
      </div>
    </Field>
    {!isB2B && (
      <Field label="Resume" hint="PDF or Drive link. Attached to outgoing emails.">
        <div style={{ display: "flex", gap: 8, padding: 12, background: "var(--bg-1)", border: "0.5px dashed var(--border-strong)", borderRadius: 7, alignItems: "center" }}>
          <Icon name="file" size={16} style={{ color: "var(--fg-2)" }} />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 12.5 }}>jordan-marsh-resume.pdf</div>
            <div style={{ fontSize: 11, color: "var(--fg-3)" }}>342 KB · Uploaded just now</div>
          </div>
          <button className="btn btn-sm">Replace</button>
        </div>
      </Field>
    )}
    <Field label="Portfolio / website" optional>
      <input className="field" placeholder="https://…" />
    </Field>
    <Field label="Calendar link" optional hint="We'll insert this in CTAs automatically.">
      <input className="field" placeholder="https://cal.com/jordan/15min" />
    </Field>
  </>
);

const StepSettings = ({ data, set }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void }) => (
  <>
    <div style={{ fontSize: 11, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 10 }}>Email sourcing</div>
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 12 }}>
      {[
        { id: "apollo", title: "Apollo API", desc: "Verified, deliverable emails. ~92% accuracy.", icon: "check", tag: "Recommended", tagClass: "b-sent" },
        { id: "scrape", title: "Web scraping", desc: "Free. Pulled from public sources.", icon: "warn", tag: "Higher bounce risk", tagClass: "b-bounced" },
      ].map((opt) => {
        const on = data.emailSource === opt.id;
        return (
          <div key={opt.id} onClick={() => set("emailSource", opt.id)} style={{ background: on ? "var(--bg-2)" : "var(--bg-1)", border: "1px solid", borderColor: on ? "var(--accent)" : "var(--border-strong)", borderRadius: 8, padding: 14, cursor: "pointer", position: "relative" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ width: 14, height: 14, borderRadius: "50%", border: "1.5px solid", borderColor: on ? "var(--accent)" : "var(--border-strong)", display: "grid", placeItems: "center" }}>
                {on && <div style={{ width: 6, height: 6, borderRadius: "50%", background: "var(--accent)" }} />}
              </div>
              <div style={{ fontSize: 13, fontWeight: 550 }}>{opt.title}</div>
            </div>
            <div style={{ fontSize: 11.5, color: "var(--fg-2)", marginTop: 8, lineHeight: 1.45 }}>{opt.desc}</div>
            <span className={`badge ${opt.tagClass}`} style={{ marginTop: 10 }}>
              <span className="badge-dot" />{opt.tag}
            </span>
          </div>
        );
      })}
    </div>

    {data.emailSource === "scrape" && (
      <div style={{ background: "rgba(232,184,122,0.08)", border: "0.5px solid rgba(232,184,122,0.3)", borderRadius: 8, padding: 14, marginBottom: 18, display: "flex", gap: 10 }}>
        <Icon name="warn" size={16} style={{ color: "var(--amber)", flexShrink: 0, marginTop: 1 }} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12.5, fontWeight: 550, color: "var(--amber)" }}>Heads up — emails sourced via scraping may be outdated</div>
          <div style={{ fontSize: 12, color: "var(--fg-1)", marginTop: 6, lineHeight: 1.55 }}>
            Scraped emails can be incorrect, role-based, or no longer monitored. Expect a bounce rate around 18–25% — significantly higher than Apollo. Repeated bounces can also affect your sender reputation.
          </div>
          <label style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 12, cursor: "pointer", fontSize: 12 }}>
            <input type="checkbox" checked={data.scrapingAck} onChange={(e) => set("scrapingAck", e.target.checked)} style={{ accentColor: "var(--amber)" }} />
            <span>I understand the risks and want to proceed with web scraping.</span>
          </label>
        </div>
      </div>
    )}

    <div style={{ fontSize: 11, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 10, marginTop: 8 }}>AI provider</div>
    <Field label="Model" hint="Used for personalization, subject lines, and reply drafting.">
      <select className="field" value={data.llm} onChange={(e) => set("llm", e.target.value)}>
        <option value="gpt-5">OpenAI · GPT-5 (recommended)</option>
        <option value="claude">Anthropic · Claude Sonnet 4.5</option>
        <option value="local">Local · Llama 3.3 70B</option>
      </select>
    </Field>
    <Field label="Tone" hint="How should drafts sound?">
      <div style={{ display: "flex", gap: 6 }}>
        {["Direct", "Warm", "Formal", "Casual"].map((t, i) => (
          <button key={t} className="btn btn-sm" style={{ background: i === 0 ? "var(--accent-dim)" : "var(--bg-1)", borderColor: i === 0 ? "var(--accent)" : "var(--border-strong)", color: i === 0 ? "var(--accent)" : "var(--fg-1)", flex: 1, justifyContent: "center" }}>{t}</button>
        ))}
      </div>
    </Field>
  </>
);

const StepReview = ({ data, isB2B, setStep }: { data: WizardData; isB2B: boolean; setStep: (n: number) => void }) => {
  const rows = [
    { label: "Campaign type", value: isB2B ? "B2B sales outreach" : "Job outreach", step: 0 },
    { label: "Intent", value: data.intent, step: 0, multi: true },
    { label: "Companies", value: data.companies.split(",").length + " companies", step: 1 },
    { label: "Titles", value: (data.titles as string[]).join(", "), step: 1 },
    { label: "Regions", value: (data.regions as string[]).join(", "), step: 1 },
    { label: "Sender", value: data.sender, step: 2 },
    { label: "Email source", value: data.emailSource === "apollo" ? "Apollo API" : "Web scraping", step: 3, warn: data.emailSource === "scrape" },
    { label: "AI model", value: ({ "gpt-5": "OpenAI GPT-5", claude: "Claude Sonnet 4.5", local: "Llama 3.3 70B" } as Record<string, string>)[data.llm], step: 3 },
  ];
  return (
    <>
      <div style={{ background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 10, overflow: "hidden", marginBottom: 18 }}>
        {rows.map((r, i) => (
          <div key={i} style={{ display: "flex", padding: "10px 14px", borderBottom: i < rows.length - 1 ? "0.5px solid var(--border)" : "none", gap: 12, alignItems: r.multi ? "flex-start" : "center" }}>
            <div style={{ width: 130, fontSize: 11.5, color: "var(--fg-2)", flexShrink: 0 }}>{r.label}</div>
            <div style={{ flex: 1, fontSize: 12.5, color: r.warn ? "var(--amber)" : "var(--fg)", lineHeight: 1.5, display: "flex", alignItems: "center", gap: 6 }}>
              {r.warn && <Icon name="warn" size={12} />}{r.value}
            </div>
            <button className="btn btn-ghost btn-sm" onClick={() => setStep(r.step)}>
              <Icon name="edit" size={11} />Edit
            </button>
          </div>
        ))}
      </div>
      <div style={{ background: "var(--bg-1)", border: "0.5px solid var(--accent)", borderRadius: 10, padding: 14, display: "flex", gap: 10, alignItems: "flex-start" }}>
        <Icon name="sparkles" size={15} style={{ color: "var(--accent)", marginTop: 2 }} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12.5, fontWeight: 550 }}>Ready to launch</div>
          <div style={{ fontSize: 12, color: "var(--fg-2)", marginTop: 4, lineHeight: 1.55 }}>
            We'll find ~150 contacts, draft personalized emails for each, and assemble your sendable list. Estimated time: <span style={{ color: "var(--fg)", fontFamily: "var(--font-mono)" }}>3–5 min</span>.
          </div>
        </div>
      </div>
    </>
  );
};

export default function WizardPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const [campaignType] = React.useState("b2b");
  const [step, setStep] = React.useState(0);
  const [data, setData] = React.useState<WizardData>({
    intent: "Pitch our observability platform to engineering leaders at Series B+ fintechs. Focus on teams suffering from MTTR pain.",
    body: "Hi {{firstName}},\n\nNoticed {{company}} just shipped real-time payments — congrats. Teams at that scale usually start hitting MTTR walls around 90 days in. We help engineering orgs cut MTTR by ~40% without ripping out their existing stack.\n\nWorth a 15-min look next week?\n\n— Jordan",
    companies: "Mercury, Ramp, Brex, Modern Treasury, Stripe Issuing, Plaid, Unit, Increase, Highnote, Lithic",
    regions: ["North America", "Europe"],
    titles: ["VP Engineering", "Head of Platform", "Director of Infrastructure"],
    companySize: "100-1000",
    industry: "Fintech / Payments",
    valueProp: "Cut MTTR by 40% with zero-instrumentation observability.",
    sender: "jordan@company.com",
    linkedin: "https://linkedin.com/in/jordan-marsh",
    emailSource: "apollo",
    scrapingAck: false,
    llm: "gpt-5",
  });

  const set = (k: keyof WizardData, v: unknown) => setData((d) => ({ ...d, [k]: v }));

  const isB2B = campaignType !== "job";
  const steps = isB2B
    ? [
        { id: "intent", title: "Intent", subtitle: "Why are you reaching out?" },
        { id: "target", title: "Target", subtitle: "Who should we contact?" },
        { id: "profile", title: "Sender", subtitle: "Who's sending these?" },
        { id: "settings", title: "Sources", subtitle: "Email + AI providers" },
        { id: "review", title: "Review", subtitle: "Confirm and launch" },
      ]
    : [
        { id: "intent", title: "Role", subtitle: "What are you looking for?" },
        { id: "target", title: "Targets", subtitle: "Where do you want to work?" },
        { id: "profile", title: "Profile", subtitle: "Resume + links" },
        { id: "settings", title: "Sources", subtitle: "Email + AI providers" },
        { id: "review", title: "Review", subtitle: "Confirm and launch" },
      ];

  const total = steps.length;
  const next = () => setStep((s) => Math.min(total - 1, s + 1));
  const prev = () => (step === 0 ? router.back() : setStep((s) => s - 1));

  const canAdvance = () => {
    if (step === 3 && data.emailSource === "scrape" && !data.scrapingAck) return false;
    return true;
  };

  const handleLaunch = async () => {
    await fetch(`/api/v1/campaigns/${id}/sessions`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ extracted_params: data }),
    });
    router.push(`/campaign/${id}/processing`);
  };

  return (
    <div className="shell">
      <Sidebar active="new" />
      <div className="main">
        <Topbar
          crumb={
            <>
              <span className="muted">New campaign</span>
              <Icon name="chev_r" size={11} className="sep" style={{ color: "var(--fg-3)" }} />
              <span>{isB2B ? "B2B sales outreach" : "Job outreach"}</span>
              <span className="badge b-draft" style={{ marginLeft: 8 }}>
                <span className="badge-dot" />Draft
              </span>
            </>
          }
          right={
            <>
              <span style={{ fontSize: 11, color: "var(--fg-3)" }}>Auto-saved 2s ago</span>
              <button className="btn btn-ghost btn-sm">Save and exit</button>
            </>
          }
        />

        <div style={{ display: "flex", flex: 1, minHeight: 0 }}>
          {/* Step rail */}
          <div style={{ width: 220, borderRight: "0.5px solid var(--border)", padding: 18, flexShrink: 0 }}>
            <div style={{ fontSize: 10.5, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)", marginBottom: 14 }}>Setup · {step + 1}/{total}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              {steps.map((s, i) => {
                const done = i < step;
                const active = i === step;
                return (
                  <div key={s.id} onClick={() => i <= step && setStep(i)} style={{ display: "flex", gap: 10, padding: "8px 8px", borderRadius: 6, background: active ? "var(--bg-2)" : "transparent", cursor: i <= step ? "pointer" : "default", alignItems: "flex-start" }}>
                    <div style={{ width: 18, height: 18, borderRadius: "50%", background: done ? "var(--accent)" : active ? "var(--bg-3)" : "var(--bg-2)", border: active ? "1px solid var(--accent)" : "0.5px solid var(--border-strong)", display: "grid", placeItems: "center", flexShrink: 0, marginTop: 1 }}>
                      {done ? <Icon name="check" size={11} stroke={2.4} style={{ color: "var(--accent-fg)" }} /> : <span style={{ fontSize: 10, fontWeight: 600, color: active ? "var(--accent)" : "var(--fg-3)", fontFamily: "var(--font-mono)" }}>{i + 1}</span>}
                    </div>
                    <div style={{ minWidth: 0 }}>
                      <div style={{ fontSize: 12.5, fontWeight: 500, color: active ? "var(--fg)" : done ? "var(--fg-1)" : "var(--fg-2)" }}>{s.title}</div>
                      <div style={{ fontSize: 11, color: "var(--fg-3)", marginTop: 1 }}>{s.subtitle}</div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div style={{ marginTop: 20, padding: 12, background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 8 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, color: "var(--fg-2)" }}>
                <Icon name="info" size={12} />Tip
              </div>
              <div style={{ fontSize: 11.5, color: "var(--fg-2)", marginTop: 6, lineHeight: 1.5 }}>
                You can paste raw notes anywhere. We'll extract structured fields from them automatically.
              </div>
            </div>
          </div>

          {/* Step content */}
          <div style={{ flex: 1, overflow: "auto", padding: "32px 48px 120px", position: "relative" }}>
            <div style={{ maxWidth: 640, margin: "0 auto" }}>
              <div style={{ fontSize: 10.5, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)" }}>Step {step + 1} of {total}</div>
              <h2 style={{ fontSize: 22, fontWeight: 600, letterSpacing: "-0.01em", margin: "6px 0 4px" }}>{steps[step].title}</h2>
              <p style={{ fontSize: 13.5, color: "var(--fg-2)", margin: "0 0 24px" }}>{steps[step].subtitle}</p>

              {step === 0 && <StepIntent data={data} set={set} isB2B={isB2B} />}
              {step === 1 && <StepTarget data={data} set={set} isB2B={isB2B} />}
              {step === 2 && <StepProfile data={data} set={set} isB2B={isB2B} />}
              {step === 3 && <StepSettings data={data} set={set} />}
              {step === 4 && <StepReview data={data} isB2B={isB2B} setStep={setStep} />}
            </div>
          </div>
        </div>

        {/* Footer nav */}
        <div style={{ height: 56, borderTop: "0.5px solid var(--border)", display: "flex", alignItems: "center", padding: "0 24px", flexShrink: 0, gap: 10, background: "var(--bg)" }}>
          <button className="btn btn-sm" onClick={prev}>
            <Icon name="arrow_l" size={12} />
            {step === 0 ? "Cancel" : "Back"}
          </button>
          <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 4 }}>
            {steps.map((_, i) => (
              <div key={i} style={{ width: 22, height: 3, borderRadius: 2, background: i <= step ? "var(--accent)" : "var(--bg-3)" }} />
            ))}
          </div>
          {step < total - 1 ? (
            <button className="btn btn-primary btn-sm" onClick={next} disabled={!canAdvance()} style={{ opacity: canAdvance() ? 1 : 0.5 }}>
              Continue
              <Icon name="arrow_r" size={12} />
            </button>
          ) : (
            <button className="btn btn-primary btn-sm" onClick={handleLaunch}>
              <Icon name="sparkles" size={12} />
              Launch campaign
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

