);

const SendModal = ({ count, onClose }: { count: number; onClose: () => void }) => {
  const [confirmed, setConfirmed] = React.useState(false);
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", backdropFilter: "blur(4px)", zIndex: 60, display: "grid", placeItems: "center" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: 440, background: "var(--bg-1)", border: "0.5px solid var(--border-strong)", borderRadius: 12, padding: 22, boxShadow: "var(--shadow-lg)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
          <div style={{ width: 36, height: 36, borderRadius: 8, background: "var(--accent-dim)", display: "grid", placeItems: "center", color: "var(--accent)" }}>
            <Icon name="send" size={16} />
