            <span style={{ color: "var(--fg-2)" }}>Connected account</span>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
              <Icon name="google" size={12} />jordan@m… <span style={{ color: "var(--accent)" }}>✓</span>
            </span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span style={{ color: "var(--fg-2)" }}>Throttle</span>
            <span>~30 emails/hour · spread over 4 hours</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span style={{ color: "var(--fg-2)" }}>Replies route to</span>
            <span>Your inbox</span>
          </div>
        </div>

        <label style={{ display: "flex", gap: 8, fontSize: 12, color: "var(--fg-1)", padding: "10px 0", cursor: "pointer" }}>
          <input type="checkbox" checked={confirmed} onChange={(e) => setConfirmed(e.target.checked)} style={{ accentColor: "var(--accent)", marginTop: 2 }} />
          <span>I've reviewed the drafts and the recipient list. Sends will start in 60 seconds and can be paused at any time.</span>
        </label>

        <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
          <button className="btn btn-sm" onClick={onClose} style={{ flex: 1, justifyContent: "center" }}>Cancel</button>
