                    </td>
                    <td style={td()}>
                      <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.contact}</div>
                      <div style={{ fontSize: 10.5, color: "var(--fg-3)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.role}</div>
                    </td>
                    <td style={{ ...td(), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11.5, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.email}</td>
                    <td style={{ ...td(), color: r.status === "draft" ? "var(--fg-3)" : "var(--fg-1)", fontStyle: r.status === "draft" ? "italic" : "normal", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.subject}</td>
                    <td style={td()}>
                      <span className={`badge ${STATUS_CLASS[r.status]} style-${badgeStyle}`}>
                        <span className="badge-dot" />{STATUS_LABEL[r.status]}
                      </span>
                    </td>
                    <td style={{ ...td("right"), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11 }}>{r.sent}</td>
                    <td style={{ ...td("right"), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11 }}>
                      <span style={{ color: r.opens > 0 ? "var(--purple)" : "var(--fg-3)" }}>{r.opens}</span>
                      <span style={{ color: "var(--fg-3)" }}> · </span>
                      <span style={{ color: r.replies > 0 ? "var(--teal)" : "var(--fg-3)" }}>{r.replies}</span>
                    </td>
                    <td style={td()}>
                      <button className="btn btn-icon btn-sm btn-ghost" onClick={(e) => e.stopPropagation()}><Icon name="settings" size={11} /></button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          <div style={{ padding: "12px 16px", color: "var(--fg-3)", fontSize: 11.5, borderTop: "0.5px solid var(--border)", display: "flex", alignItems: "center", gap: 12 }}>
            <span>Showing {filtered.length} of {ROWS.length}</span>
            <span>·</span>
            <span>Last sync 2 min ago</span>
            <div style={{ flex: 1 }} />
            <span style={{ fontFamily: "var(--font-mono)" }}>↑↓ navigate · ⏎ open · ⌘A select all</span>
          </div>
        </div>
      </div>

      {drawer && <Drawer row={drawer} onClose={() => setDrawer(null)} />}
      {showSend && <SendModal count={selected.size > 0 ? selected.size : ROWS.filter((r) => r.status === "ready").length} onClose={() => setShowSend(false)} />}
    </div>
  );
}

