const SendModal = ({ count, onClose }: { count: number; onClose: () => void }) => {
  const [confirmed, setConfirmed] = React.useState(false);
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", backdropFilter: "blur(4px)", zIndex: 60, display: "grid", placeItems: "center" }}>
