            <span style={{ color: "var(--fg-2)" }}>Connected account</span>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
              <Icon name="google" size={12} />jordan@m… <span style={{ color: "var(--accent)" }}>✓</span>
            </span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span style={{ color: "var(--fg-2)" }}>Throttle</span>
            <span>~30 emails/hour · spread over 4 hours</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span style={{ color: "var(--fg-2)" }}>Replies route to</span>
            <span>Your inbox</span>
          </div>
        </div>

        <label style={{ display: "flex", gap: 8, fontSize: 12, color: "var(--fg-1)", padding: "10px 0", cursor: "pointer" }}>
          <input type="checkbox" checked={confirmed} onChange={(e) => setConfirmed(e.target.checked)} style={{ accentColor: "var(--accent)", marginTop: 2 }} />
          <span>I've reviewed the drafts and the recipient list. Sends will start in 60 seconds and can be paused at any time.</span>
        </label>

        <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
          <button className="btn btn-sm" onClick={onClose} style={{ flex: 1, justifyContent: "center" }}>Cancel</button>
          <button className="btn btn-primary btn-sm" disabled={!confirmed} onClick={onClose} style={{ flex: 2, justifyContent: "center", opacity: confirmed ? 1 : 0.5 }}>
            <Icon name="send" size={12} />Send {count}
          </button>
        </div>
      </div>
    </div>
  );
};

export default function DashboardPage() {
  const { id } = useParams<{ id: string }>();
  const [selected, setSelected] = React.useState(new Set([1, 4, 7]));
  const [drawer, setDrawer] = React.useState<Row | null>(null);
  const [showSend, setShowSend] = React.useState(false);
  const [search, setSearch] = React.useState("");
  const [statusFilter, setStatusFilter] = React.useState("all");

  const badgeStyle = "pill";
  const density = "compact";
  const rowH = density === "comfy" ? 40 : 32;

  const toggle = (i: number) => {
    const n = new Set(selected);
    n.has(i) ? n.delete(i) : n.add(i);
    setSelected(n);
  };

  const filtered = ROWS.filter((r) => {
    if (statusFilter !== "all" && r.status !== statusFilter) return false;
    if (search && !(r.co + r.contact + r.email).toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const stats = {
    total: ROWS.length,
    sent: ROWS.filter((r) => ["sent", "opened", "replied"].includes(r.status)).length,
    opened: ROWS.filter((r) => ["opened", "replied"].includes(r.status)).length,
    replied: ROWS.filter((r) => r.status === "replied").length,
    bounced: ROWS.filter((r) => r.status === "bounced").length,
    pending: ROWS.filter((r) => ["draft", "ready"].includes(r.status)).length,
