"use client";

import React, { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { AppShell } from "@/components/layout/AppShell";
import { Badge } from "@/components/ui/Badge";
import { Button } from "@/components/ui/Button";
import type { Campaign } from "@/types";

export default function DashboardPage() {
  const router = useRouter();
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem("outreach_token");
    if (!token) {
      router.replace("/auth");
      return;
    }

    fetch("/api/v1/campaigns")
      .then((r) => r.json())
      .then((data) => {
        setCampaigns(data.campaigns || []);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [router]);

  const formatDate = (dateStr: string) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });

  return (
    <AppShell
      breadcrumbs={[{ label: "Dashboard" }]}
      actions={
        <Button variant="primary" size="sm" onClick={() => router.push("/campaign/new")}>
          + New Campaign
        </Button>
      }
    >
      <div style={{ maxWidth: "900px" }}>
        <div style={{ marginBottom: "24px" }}>
          <h1 style={{ fontSize: "20px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
            Your Campaigns
          </h1>
          <p style={{ fontSize: "13px", color: "var(--fg-2)" }}>
            Manage and track all your outreach campaigns
          </p>
        </div>

        {loading ? (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              height: "200px",
              color: "var(--fg-3)",
              fontSize: "13px",
            }}
          >
            Loading campaigns...
          </div>
        ) : campaigns.length === 0 ? (
          <div
            style={{
              border: "1px dashed var(--border)",
              borderRadius: "12px",
              padding: "48px",
              textAlign: "center",
            }}
          >
            <p style={{ color: "var(--fg-2)", marginBottom: "16px", fontSize: "14px" }}>
              No campaigns yet. Create your first one!
            </p>
            <Button variant="primary" onClick={() => router.push("/campaign/new")}>
              + New Campaign
            </Button>
          </div>
        ) : (
          <div
            style={{
              border: "1px solid var(--border)",
              borderRadius: "10px",
              overflow: "hidden",
            }}
          >
            {/* Table header */}
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 120px 120px 140px 80px",
                padding: "10px 16px",
                background: "var(--bg-2)",
                borderBottom: "1px solid var(--border)",
              }}
            >
              {["Campaign", "Type", "Status", "Created", ""].map((h) => (
                <span
                  key={h}
                  style={{
                    fontSize: "11px",
                    fontWeight: 600,
                    color: "var(--fg-3)",
                    textTransform: "uppercase",
                    letterSpacing: "0.06em",
                  }}
                >
                  {h}
                </span>
              ))}
            </div>

            {/* Rows */}
            {campaigns.map((c, i) => (
              <div
                key={c.id}
                style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 120px 120px 140px 80px",
                  padding: "12px 16px",
                  alignItems: "center",
                  borderBottom: i < campaigns.length - 1 ? "1px solid var(--border)" : "none",
                  background: "var(--bg-1)",
                  transition: "background 0.1s",
                }}
                onMouseEnter={(e) => (e.currentTarget.style.background = "var(--bg-2)")}
                onMouseLeave={(e) => (e.currentTarget.style.background = "var(--bg-1)")}
              >
                <div>
                  <div style={{ fontSize: "13px", fontWeight: 500, color: "var(--fg)", textTransform: "capitalize" }}>
                    {c.type.replace(/_/g, " ")}
                  </div>
                  <div style={{ fontSize: "11px", color: "var(--fg-3)", marginTop: "2px" }}>
                    ID: {c.id.slice(0, 12)}...
                  </div>
                </div>
                <div>
                  <Badge label={c.type} />
                </div>
                <div>
                  <Badge label={c.status} />
                </div>
                <div style={{ fontSize: "12px", color: "var(--fg-2)" }}>
                  {formatDate(c.created_at)}
                </div>
                <div>
                  <Link
                    href={`/campaign/${c.id}/dashboard`}
                    style={{
                      fontSize: "12px",
                      color: "var(--accent)",
                      fontWeight: 500,
                    }}
                  >
                    View →
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </AppShell>
  );
}

