from enum import Enum
from app.interfaces.llm_provider import AbstractLLMProvider
from app.core.exceptions import LLMUnavailableError

FIRST_MESSAGES = {
    "job_outreach": (
        "I'd love to help you with your job outreach campaign! Let's start — "
        "what role are you targeting and which companies interest you?"
    ),
    "b2b": "Let's build your B2B outreach campaign! Who are you trying to reach and what are you pitching?",
    "hiring": (
        "Great, let's find you some candidates! What role are you hiring for "
        "and what kind of profile are you looking for?"
    ),
    "pr": (
        "Let's craft your PR outreach! What's the story you're pitching "
        "and which publications are you targeting?"
    ),
    "fundraising": (
        "Let's get your investor outreach started! What stage are you at "
        "and what kind of investors are you targeting?"
    ),
    "partnership": (
        "Let's find you some partners! What kind of partnership are you looking for "
        "and which companies interest you?"
    ),
}


class LLMMode(str, Enum):
    CHAT = "chat"
    GENERATION = "generation"
    EXTRACTION = "extraction"


class LLMService:
    def __init__(self, provider: AbstractLLMProvider, model: str = "gpt-4o"):
        self.provider = provider
        self.model = model

    def get_first_message(self, campaign_type: str) -> str:
        return FIRST_MESSAGES.get(campaign_type, "Tell me about your outreach goals!")

    async def chat_completion(
        self, messages: list[dict], system_prompt: str, model: str | None = None
    ) -> str:
        try:
            return await self.provider.chat_completion(messages, system_prompt, model or self.model)
        except Exception as e:
            raise LLMUnavailableError(f"LLM provider failed: {e}")

    async def extract_params(self, messages: list[dict], campaign_type: str) -> dict:
        system_prompt = (
            f"You are an AI assistant that extracts structured campaign parameters from a conversation.\n"
            f"Campaign type: {campaign_type}\n"
            "Extract the following fields where mentioned: geography, target_strategy, purpose, "
            "email_source (apollo or scrape), llm_provider (openai/anthropic), experience_level.\n"
            "Return a JSON object with only the fields mentioned."
        )
        try:
            return await self.provider.structured_completion(messages, system_prompt, self.model)
        except Exception as e:
            raise LLMUnavailableError(f"Param extraction failed: {e}")

    async def generate_email(
        self, contact: dict, session_params: dict, sender_profile: dict
    ) -> dict:
        system_prompt = (
            "You are an expert at writing personalized cold outreach emails.\n"
            "Generate a compelling, personalized email based on the contact information and campaign parameters.\n"
            "Return JSON with keys: subject, body"
        )
        messages = [
            {
                "role": "user",
                "content": (
                    f"Contact:\n"
                    f"- Company: {contact.get('company')}\n"
                    f"- Person: {contact.get('person_name', 'Hiring Manager')}\n"
                    f"- Title: {contact.get('title', 'Unknown')}\n"
                    f"- Email: {contact.get('email')}\n\n"
                    f"Campaign purpose: {session_params.get('purpose', '')}\n"
                    f"Target strategy: {session_params.get('target_strategy', '')}\n"
                    f"Sender: {sender_profile.get('email', '')}\n\n"
                    "Write a personalized, concise cold email (under 150 words). "
                    "Return JSON with subject and body keys."
                ),
            }
        ]
        try:
            return await self.provider.structured_completion(messages, system_prompt, self.model)
        except Exception as e:
            raise LLMUnavailableError(f"Email generation failed: {e}")

import json
from openai import AsyncOpenAI
from app.interfaces.llm_provider import AbstractLLMProvider
from app.config import settings


class OpenAIProvider(AbstractLLMProvider):
    def __init__(self):
        self.client = AsyncOpenAI(api_key=settings.OPENAI_API_KEY)

    async def chat_completion(
        self, messages: list[dict], system_prompt: str, model: str
    ) -> str:
        msgs = [{"role": "system", "content": system_prompt}] + messages
        response = await self.client.chat.completions.create(model=model, messages=msgs)
        return response.choices[0].message.content

    async def structured_completion(
        self, messages: list[dict], system_prompt: str, model: str
    ) -> dict:
        msgs = [
            {"role": "system", "content": system_prompt + "\n\nRespond with valid JSON only."}
        ] + messages
        response = await self.client.chat.completions.create(
            model=model, messages=msgs, response_format={"type": "json_object"}
        )
        return json.loads(response.choices[0].message.content)

