export async function GET() {
  return NextResponse.json({
    campaigns: [
      {
        id: "uuid-1",
        type: "job_outreach",
        status: "ready",
        created_at: "2026-05-01T10:00:00Z",
      },
      {
        id: "uuid-2",
        type: "b2b",
        status: "draft",
        created_at: "2026-05-02T10:00:00Z",
      },
      {
        id: "uuid-3",
        type: "investor_outreach",
        status: "processing",
        created_at: "2026-05-03T10:00:00Z",
      },
    ],
    total: 3,
  });
}

export async function POST(request: NextRequest) {
  const body = await request.json().catch(() => ({}));
  const type = body.type || "b2b";

  const firstMessages: Record<string, string> = {
    job_outreach:
      "I'd love to help you with your job outreach campaign! Let's start — what role are you targeting and which companies interest you?",
    b2b:
      "Great! Let's set up your B2B sales outreach. Who is your ideal customer profile and what product/service are you pitching?",
    investor_outreach:
      "Let's craft your investor outreach. What stage is your startup, and what types of investors are you targeting?",
    custom:
      "I'll help you build a custom outreach campaign. Tell me about your goal and target audience.",
  };

  return NextResponse.json({
    campaign_id: `campaign-${Date.now()}`,
    session_id: `session-${Date.now()}`,
    status: "draft",
    first_message: firstMessages[type] || firstMessages.b2b,
  });
}

