"use client";

import React from "react";
import { useRouter } from "next/navigation";
import { Icon } from "@/components/ui/Icon";

const PasswordMeter = ({ value }: { value: string }) => {
  const score = Math.min(4, Math.floor(
    (value.length >= 8 ? 1 : 0) +
    (/[A-Z]/.test(value) ? 1 : 0) +
    (/[0-9]/.test(value) ? 1 : 0) +
    (/[^A-Za-z0-9]/.test(value) ? 1 : 0)
  ));
  const labels = ["Too short", "Weak", "Okay", "Good", "Strong"];
  const colors = ["#3a3f46", "#e8917a", "#e8b87a", "#7aa7e8", "#7dd3a0"];
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 8 }}>
      <div style={{ display: "flex", gap: 3, flex: 1 }}>
        {[0, 1, 2, 3].map((i) => (
          <div key={i} style={{ flex: 1, height: 3, borderRadius: 2, background: i < score ? colors[score] : "var(--bg-3)", transition: "background .2s" }} />
        ))}
      </div>
      <span style={{ fontSize: 10.5, color: "var(--fg-3)", fontFamily: "var(--font-mono)", minWidth: 55, textAlign: "right" }}>
        {value ? labels[score] : ""}
      </span>
    </div>
  );
};

const Field = ({ label, children, right }: { label: string; children: React.ReactNode; right?: React.ReactNode }) => (
  <div>
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
      <label style={{ fontSize: 11.5, fontWeight: 500, color: "var(--fg-1)" }}>{label}</label>
      {right}
    </div>
    {children}
  </div>
);

export default function AuthPage() {
  const router = useRouter();
  const [mode, setMode] = React.useState<"signin" | "signup">("signin");
  const isSignup = mode === "signup";
  const [email, setEmail] = React.useState("");
  const [password, setPassword] = React.useState("");
  const [name, setName] = React.useState("");
  const [company, setCompany] = React.useState("");
  const [agree, setAgree] = React.useState(false);

  const canSubmit = isSignup
    ? name && company && /\S+@\S+\.\S+/.test(email) && password.length >= 8 && agree
    : /\S+@\S+\.\S+/.test(email) && password.length >= 6;

  const handleContinue = () => {
    localStorage.setItem("outreach_token", "mock-token");
    router.push("/campaign/new");
  };

  return (
    <div style={{ height: "100%", width: "100%", background: "var(--bg)", color: "var(--fg)", display: "flex", position: "relative", overflow: "hidden" }}>
      {/* Left — animated brand panel */}
      <div className="auth-left">
        <div className="cb-aurora auth-aurora" aria-hidden="true">
          <div className="cb-blob cb-blob-1" />
          <div className="cb-blob cb-blob-2" />
          <div className="cb-blob cb-blob-3" />
        </div>
        <div className="cb-grid" aria-hidden="true" />
        <div style={{ position: "relative", zIndex: 2, padding: "32px 40px", display: "flex", flexDirection: "column", height: "100%" }}>
          <div className="sb-brand" style={{ padding: 0 }}>
            <div className="sb-brand-mark">O</div>
            <div>Outreach</div>
          </div>
          <div style={{ flex: 1 }} />
          <div style={{ maxWidth: 440 }}>
            <div className="cb-pill" style={{ marginBottom: 22 }}>
              <span className="cb-pill-dot" />
              <span>Trusted by 2,400+ founders &amp; recruiters</span>
            </div>
            <h2 style={{ fontSize: 36, fontWeight: 600, letterSpacing: "-0.022em", margin: 0, lineHeight: 1.1 }}>
              Personalized outreach,<br />
              <span className="cb-shimmer" style={{ fontStyle: "italic", fontWeight: 500 }}>without the busywork.</span>
            </h2>
            <p style={{ fontSize: 14.5, color: "var(--fg-2)", marginTop: 16, lineHeight: 1.55 }}>
              Describe who you want to reach. We'll find them, draft personalized emails, and let you send from your own inbox — typically in under 4 minutes.
            </p>
            <div style={{ display: "flex", flexDirection: "column", gap: 10, marginTop: 26 }}>
              {[
                "Apollo + verified email sourcing",
                "Per-contact research with GPT-5",
                "Send from Gmail · live opens & replies",
              ].map((t) => (
                <div key={t} style={{ display: "flex", gap: 10, alignItems: "center", fontSize: 13, color: "var(--fg-1)" }}>
                  <span style={{ width: 18, height: 18, borderRadius: 5, background: "var(--accent-dim)", border: "0.5px solid var(--accent)", color: "var(--accent)", display: "grid", placeItems: "center" }}>
                    <Icon name="check" size={11} stroke={2.6} />
                  </span>
                  {t}
                </div>
              ))}
            </div>
          </div>
          <div style={{ flex: 1 }} />
          <div style={{ fontSize: 11.5, color: "var(--fg-3)", display: "flex", gap: 14 }}>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 5 }}><Icon name="lock" size={11} />SOC 2</span>
            <span>·</span>
            <span>GDPR ready</span>
            <span>·</span>
            <span>End-to-end encrypted</span>
          </div>
        </div>
      </div>

      {/* Right — form */}
      <div className="auth-right">
        <div style={{ position: "absolute", top: 20, right: 24, fontSize: 12, color: "var(--fg-2)" }}>
          {isSignup ? "Already have an account?" : "New to Outreach?"}
          <button className="btn btn-ghost btn-sm" style={{ marginLeft: 8, color: "var(--accent)" }} onClick={() => setMode(isSignup ? "signin" : "signup")}>
            {isSignup ? "Sign in" : "Create account"}
          </button>
        </div>

        <div className="auth-form">
          <h1 style={{ fontSize: 28, fontWeight: 600, letterSpacing: "-0.018em", margin: 0 }}>
            {isSignup ? "Create your account" : "Welcome back"}
          </h1>
          <p style={{ fontSize: 13.5, color: "var(--fg-2)", marginTop: 8, marginBottom: 26 }}>
            {isSignup ? "Start your first campaign in under 5 minutes. No credit card required." : "Sign in to keep working on your campaigns."}
          </p>

          <button className="btn" style={{ width: "100%", justifyContent: "center", height: 40, fontSize: 13.5, fontWeight: 500, background: "var(--bg-1)" }} onClick={handleContinue}>
            <Icon name="google" size={15} />Continue with Google
          </button>
          <button className="btn" style={{ width: "100%", justifyContent: "center", height: 40, fontSize: 13.5, fontWeight: 500, background: "var(--bg-1)", marginTop: 8 }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 .297c-6.63 0-12 5.373-12 12 0 5.303 3.438 9.8 8.205 11.385.6.111.82-.261.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61-.546-1.385-1.335-1.755-1.335-1.755-1.087-.744.084-.729.084-.729 1.205.084 1.838 1.236 1.838 1.236 1.07 1.835 2.809 1.305 3.495.998.108-.776.417-1.305.76-1.605-2.665-.305-5.466-1.332-5.466-5.93 0-1.31.465-2.38 1.235-3.22-.135-.303-.54-1.523.105-3.176 0 0 1.005-.322 3.3 1.23.96-.267 1.98-.4 3-.405 1.02.005 2.04.138 3 .405 2.28-1.552 3.285-1.23 3.285-1.23.645 1.653.24 2.873.12 3.176.765.84 1.23 1.91 1.23 3.22 0 4.61-2.805 5.625-5.475 5.92.42.36.81 1.096.81 2.22 0 1.606-.015 2.896-.015 3.286 0 .315.21.69.825.57C20.565 22.092 24 17.592 24 12.297c0-6.627-5.373-12-12-12" /></svg>
            Continue with GitHub
          </button>

          <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "22px 0 18px", color: "var(--fg-3)", fontSize: 11 }}>
            <div style={{ flex: 1, height: 1, background: "var(--border)" }} />
            <span style={{ fontFamily: "var(--font-mono)" }}>OR</span>
            <div style={{ flex: 1, height: 1, background: "var(--border)" }} />
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {isSignup && (
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                <Field label="Full name">
                  <input className="field" placeholder="Jane Cooper" value={name} onChange={(e) => setName(e.target.value)} />
                </Field>
                <Field label="Company">
                  <input className="field" placeholder="Acme Inc." value={company} onChange={(e) => setCompany(e.target.value)} />
                </Field>
              </div>
            )}
            <Field label="Work email">
              <input className="field" type="email" placeholder="you@company.com" value={email} onChange={(e) => setEmail(e.target.value)} />
            </Field>
            <Field
              label="Password"
              right={!isSignup ? <a href="#" style={{ fontSize: 11, color: "var(--accent)", textDecoration: "none" }}>Forgot?</a> : undefined}
            >
              <input className="field" type="password" placeholder={isSignup ? "At least 8 characters" : "••••••••"} value={password} onChange={(e) => setPassword(e.target.value)} />
              {isSignup && <PasswordMeter value={password} />}
            </Field>

            {isSignup && (
              <label style={{ display: "flex", gap: 8, alignItems: "flex-start", fontSize: 12, color: "var(--fg-2)", lineHeight: 1.5, marginTop: 4, cursor: "pointer" }}>
                <input type="checkbox" checked={agree} onChange={(e) => setAgree(e.target.checked)} style={{ marginTop: 2, accentColor: "var(--accent)" }} />
                <span>I agree to the <a href="#" style={{ color: "var(--accent)" }}>Terms</a> and <a href="#" style={{ color: "var(--accent)" }}>Privacy Policy</a>. I will only contact people who could plausibly want to hear from me.</span>
              </label>
            )}
          </div>

          <button
            className="btn btn-primary"
            disabled={!canSubmit}
            onClick={handleContinue}
            style={{ width: "100%", justifyContent: "center", height: 42, marginTop: 22, fontSize: 13.5, fontWeight: 550, opacity: canSubmit ? 1 : 0.5 }}
          >
            {isSignup ? "Create account" : "Sign in"}
            <Icon name="arrow_r" size={13} />
          </button>

          {!isSignup && (
            <div style={{ marginTop: 20, padding: 12, border: "0.5px dashed var(--border-strong)", borderRadius: 8, fontSize: 11.5, color: "var(--fg-3)", display: "flex", gap: 10, alignItems: "center" }}>
              <Icon name="info" size={13} />
              SSO available for teams. Use your work email to discover your org.
            </div>
          )}

          <div style={{ marginTop: 28, fontSize: 11, color: "var(--fg-3)", textAlign: "center" }}>
            By continuing you agree to our <a href="#" style={{ color: "var(--fg-2)" }}>Terms</a> and <a href="#" style={{ color: "var(--fg-2)" }}>Privacy Policy</a>.
          </div>
        </div>
      </div>
    </div>
  );
}
