"use client";

import React from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Sidebar } from "@/components/layout/Sidebar";
import { Topbar } from "@/components/layout/Topbar";
import { Icon } from "@/components/ui/Icon";

interface Campaign {
  id: string;
  type: string;
  status: string;
  created_at: string;
}

const STATUS_CLASS: Record<string, string> = {
  draft: "b-draft", ready: "b-ready", processing: "b-ready", sent: "b-sent", active: "b-sent",
};

export default function DashboardPage() {
  const router = useRouter();
  const [campaigns, setCampaigns] = React.useState<Campaign[]>([]);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    const token = typeof window !== "undefined" ? localStorage.getItem("outreach_token") : null;
    if (!token) { router.replace("/auth"); return; }
    fetch("/api/v1/campaigns")
      .then((r) => r.json())
      .then((data) => { setCampaigns(data.campaigns || []); setLoading(false); })
      .catch(() => setLoading(false));
  }, [router]);

  return (
    <div className="shell">
      <Sidebar active="dashboard" />
      <div className="main">
        <Topbar
          crumb={<span style={{ fontWeight: 550 }}>Campaigns</span>}
          right={
            <button className="btn btn-primary btn-sm" onClick={() => router.push("/campaign/new")}>
              <Icon name="plus" size={12} />New campaign
            </button>
          }
        />
        <div style={{ flex: 1, overflow: "auto", padding: "24px 28px" }}>
          <div style={{ maxWidth: 860 }}>
            <div style={{ marginBottom: 20 }}>
              <h1 style={{ fontSize: 18, fontWeight: 600, color: "var(--fg)", margin: 0 }}>Your campaigns</h1>
              <p style={{ fontSize: 12.5, color: "var(--fg-2)", marginTop: 4 }}>All active and draft outreach campaigns</p>
            </div>

            {loading ? (
              <div style={{ color: "var(--fg-3)", fontSize: 13, padding: "40px 0", textAlign: "center" }}>
                <span className="spinner" style={{ display: "inline-block", marginRight: 8 }} />
                Loading…
              </div>
            ) : campaigns.length === 0 ? (
              <div style={{ border: "0.5px dashed var(--border-strong)", borderRadius: 10, padding: 48, textAlign: "center" }}>
                <p style={{ color: "var(--fg-2)", marginBottom: 16, fontSize: 13.5 }}>No campaigns yet. Create your first one!</p>
                <button className="btn btn-primary btn-sm" onClick={() => router.push("/campaign/new")}>
                  <Icon name="plus" size={12} />New campaign
                </button>
              </div>
            ) : (
              <div style={{ background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 10, overflow: "hidden" }}>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 140px 110px 130px 60px", padding: "8px 14px", borderBottom: "0.5px solid var(--border)", background: "var(--bg-2)" }}>
                  {["Campaign", "Type", "Status", "Created", ""].map((h) => (
                    <span key={h} style={{ fontSize: 10.5, fontWeight: 500, color: "var(--fg-3)", textTransform: "uppercase", letterSpacing: "0.06em" }}>{h}</span>
                  ))}
                </div>
                {campaigns.map((c, i) => (
                  <div
                    key={c.id}
                    style={{ display: "grid", gridTemplateColumns: "1fr 140px 110px 130px 60px", padding: "11px 14px", alignItems: "center", borderBottom: i < campaigns.length - 1 ? "0.5px solid var(--border)" : "none", transition: "background .1s" }}
                    onMouseEnter={(e) => (e.currentTarget.style.background = "var(--bg-2)")}
                    onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
                  >
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 500, color: "var(--fg)", textTransform: "capitalize" }}>{c.type.replace(/_/g, " ")}</div>
                      <div style={{ fontSize: 10.5, color: "var(--fg-3)", marginTop: 2, fontFamily: "var(--font-mono)" }}>{c.id.slice(0, 14)}…</div>
                    </div>
                    <div>
                      <span style={{ fontSize: 11.5, color: "var(--fg-2)", background: "var(--bg-3)", padding: "2px 7px", borderRadius: 4, border: "0.5px solid var(--border)" }}>{c.type.replace(/_/g, " ")}</span>
                    </div>
                    <div>
                      <span className={`badge ${STATUS_CLASS[c.status] || "b-draft"}`}>
                        <span className="badge-dot" />{c.status}
                      </span>
                    </div>
                    <div style={{ fontSize: 11.5, color: "var(--fg-2)" }}>
                      {new Date(c.created_at).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                    </div>
                    <div>
                      <Link href={`/campaign/${c.id}/dashboard`} style={{ fontSize: 12, color: "var(--accent)", fontWeight: 500 }}>View →</Link>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

