export async function listCampaigns(): Promise<CampaignListResponse> {
  return apiFetch("/api/v1/campaigns");
}

export async function createCampaign(
  type: Campaign["type"]
): Promise<CampaignCreateResponse> {
  return apiFetch("/api/v1/campaigns", {
    method: "POST",
    body: JSON.stringify({ type }),
  });
}

export async function getCampaign(id: string): Promise<Campaign> {
  return apiFetch(`/api/v1/campaigns/${id}`);
}

export async function getChatHistory(
  campaignId: string
): Promise<ChatHistoryResponse> {
  return apiFetch(`/api/v1/campaigns/${campaignId}/chat`);
}

export async function* sendChatMessage(
  campaignId: string,
  message: string
): AsyncGenerator<{ type: "token" | "done"; content?: string; extracted_params?: Record<string, unknown> }> {
  const token = getToken();
  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (token) headers["Authorization"] = `Bearer ${token}`;

  const res = await fetch(`${BASE_URL}/api/v1/campaigns/${campaignId}/chat`, {
    method: "POST",
    headers,
    body: JSON.stringify({ message }),
  });

  if (!res.ok || !res.body) throw new Error("Chat stream failed");

  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split("\n");
    buffer = lines.pop() ?? "";
    for (const line of lines) {
      if (line.startsWith("data: ")) {
        try {
          yield JSON.parse(line.slice(6));
        } catch {
          // skip malformed
        }
      }
    }
  }
}

export async function listOutreach(
  campaignId: string,
  page = 1,
  limit = 20
): Promise<OutreachListResponse> {
  return apiFetch(
    `/api/v1/campaigns/${campaignId}/outreach?page=${page}&limit=${limit}`
  );
}

export async function updateOutreach(
  campaignId: string,
  outreachId: string,
  status: "approved" | "rejected"
): Promise<void> {
  return apiFetch(`/api/v1/campaigns/${campaignId}/outreach/${outreachId}`, {
    method: "PATCH",
    body: JSON.stringify({ draft_status: status }),
  });
}

export async function listEmailJobs(
  campaignId: string
): Promise<EmailJobsResponse> {
  return apiFetch(`/api/v1/campaigns/${campaignId}/email-jobs`);
}

export async function enqueueEmails(
  campaignId: string,
  outreach_ids: string[] | "all"
): Promise<EnqueueResponse> {
  return apiFetch(`/api/v1/campaigns/${campaignId}/email-jobs`, {
    method: "POST",
    body: JSON.stringify({ outreach_ids }),
  });
}

export async function getCampaignStats(
  campaignId: string
): Promise<CampaignStats> {
  return apiFetch(`/api/v1/campaigns/${campaignId}/stats`);
}

export function openCampaignStream(
  campaignId: string,
  onEvent: (event: Record<string, unknown>) => void,
  onClose: () => void
): () => void {
  const token = getToken();
  const url = `${BASE_URL}/api/v1/campaigns/${campaignId}/stream${token ? `?token=${token}` : ""}`;
  const es = new EventSource(url);
  es.onmessage = (e) => {
    try {
      const data = JSON.parse(e.data);
      onEvent(data);
      if (data.type === "complete") {
        es.close();
        onClose();
      }
    } catch {
      // skip
    }
  };
  es.onerror = () => { es.close(); onClose(); };
  return () => es.close();
}

