              <div style={{ width: 1, height: 18, background: "var(--border)" }} />
              <button className="btn btn-primary btn-sm" onClick={() => setShowSend(true)}>
                <Icon name="send" size={12} />Send {selected.size > 0 ? `(${selected.size})` : "all"}
              </button>
            </>
          }
        />

        {/* Stats strip */}
        <div style={{ display: "flex", padding: "14px 16px", gap: 0, borderBottom: "0.5px solid var(--border)", flexShrink: 0 }}>
          {[
            { label: "Total", value: stats.total, color: "var(--fg)" },
            { label: "Ready", value: stats.pending, color: "var(--blue)" },
            { label: "Sent", value: stats.sent, color: "var(--accent)" },
            { label: "Opened", value: stats.opened, color: "var(--purple)" },
            { label: "Replied", value: stats.replied, color: "var(--teal)" },
            { label: "Bounced", value: stats.bounced, color: "var(--red)" },
          ].map((s, i, a) => (
            <div key={s.label} style={{ flex: 1, padding: "0 18px", borderRight: i < a.length - 1 ? "0.5px solid var(--border)" : "none" }}>
              <div style={{ fontSize: 10.5, fontWeight: 500, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--fg-3)" }}>{s.label}</div>
              <div style={{ fontSize: 22, fontWeight: 600, color: s.color, fontVariantNumeric: "tabular-nums", marginTop: 4, letterSpacing: "-0.01em" }}>{s.value}</div>
              <div style={{ fontSize: 10.5, color: "var(--fg-3)", marginTop: 1 }}>
                {s.label === "Replied" ? `${stats.sent ? Math.round((stats.replied / stats.sent) * 100) : 0}% of sent` : ""}
                {s.label === "Opened" ? `${stats.sent ? Math.round((stats.opened / stats.sent) * 100) : 0}% open rate` : ""}
              </div>
            </div>
          ))}
        </div>

        {/* Toolbar */}
        <div style={{ display: "flex", alignItems: "center", padding: "8px 14px", gap: 8, borderBottom: "0.5px solid var(--border)", flexShrink: 0 }}>
          <div style={{ position: "relative", flex: "0 1 280px" }}>
            <Icon name="search" size={12} style={{ position: "absolute", left: 9, top: 8, color: "var(--fg-3)" }} />
            <input className="field" value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search company, contact, email…" style={{ paddingLeft: 28, height: 28, fontSize: 12 }} />
          </div>
          <div style={{ display: "flex", gap: 2, padding: 2, background: "var(--bg-1)", borderRadius: 6, border: "0.5px solid var(--border)" }}>
            {["all", "ready", "sent", "opened", "replied", "bounced"].map((s) => (
              <button key={s} onClick={() => setStatusFilter(s)} className="btn btn-sm" style={{ height: 22, padding: "0 9px", border: 0, background: statusFilter === s ? "var(--bg-3)" : "transparent", color: statusFilter === s ? "var(--fg)" : "var(--fg-2)", textTransform: s === "all" ? "none" : "capitalize", fontSize: 11.5 }}>
                {s === "all" ? "All" : STATUS_LABEL[s]}
              </button>
            ))}
          </div>
          <button className="btn btn-sm"><Icon name="filter" size={12} />Filter</button>
          <button className="btn btn-sm"><Icon name="layers" size={12} />Group</button>
          <div style={{ flex: 1 }} />
          {selected.size > 0 && (
            <>
              <span style={{ fontSize: 11.5, color: "var(--fg-2)" }}>{selected.size} selected</span>
              <button className="btn btn-sm" onClick={() => setShowSend(true)}><Icon name="send" size={12} />Send</button>
              <button className="btn btn-sm"><Icon name="edit" size={12} />Edit</button>
              <button className="btn btn-sm"><Icon name="trash" size={12} />Delete</button>
              <div style={{ width: 1, height: 18, background: "var(--border)" }} />
            </>
          )}
          <button className="btn btn-icon btn-sm"><Icon name="settings" size={12} /></button>
        </div>

        {/* Table */}
        <div style={{ flex: 1, overflow: "auto", display: "flex", flexDirection: "column" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12.5, tableLayout: "fixed" }}>
            <colgroup>
              <col style={{ width: 36 }} />
              <col style={{ width: 180 }} />
              <col style={{ width: 170 }} />
              <col style={{ width: 200 }} />
              <col style={{ width: "100%" }} />
              <col style={{ width: 96 }} />
              <col style={{ width: 78 }} />
              <col style={{ width: 70 }} />
              <col style={{ width: 50 }} />
            </colgroup>
            <thead>
              <tr style={{ position: "sticky", top: 0, background: "var(--bg)", zIndex: 1 }}>
                <th style={th()}><input type="checkbox" checked={selected.size === filtered.length && filtered.length > 0} onChange={(e) => setSelected(e.target.checked ? new Set(filtered.map((_, i) => i)) : new Set())} /></th>
                <th style={th()}>Company</th>
                <th style={th()}>Contact</th>
                <th style={th()}>Email</th>
                <th style={th()}>Subject line</th>
                <th style={th()}>Status</th>
                <th style={th("right")}>Sent</th>
                <th style={th("right")}>Opens · Replies</th>
                <th style={th()}></th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((r, i) => {
                const sel = selected.has(i);
                return (
                  <tr
                    key={i}
                    onClick={() => setDrawer(r)}
                    style={{ cursor: "pointer", height: rowH, borderBottom: "0.5px solid var(--border)", background: sel ? "rgba(125,211,160,0.04)" : "transparent" }}
                    onMouseEnter={(e) => (e.currentTarget.style.background = sel ? "rgba(125,211,160,0.07)" : "var(--bg-1)")}
                    onMouseLeave={(e) => (e.currentTarget.style.background = sel ? "rgba(125,211,160,0.04)" : "transparent")}
                  >
                    <td style={td()} onClick={(e) => { e.stopPropagation(); toggle(i); }}>
                      <input type="checkbox" checked={sel} onChange={() => {}} />
                    </td>
                    <td style={td()}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8, minWidth: 0 }}>
                        <Avatar co={r.co} color={r.color} />
                        <span style={{ fontWeight: 500, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.co}</span>
                      </div>
                    </td>
                    <td style={td()}>
                      <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.contact}</div>
                      <div style={{ fontSize: 10.5, color: "var(--fg-3)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.role}</div>
                    </td>
                    <td style={{ ...td(), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11.5, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.email}</td>
                    <td style={{ ...td(), color: r.status === "draft" ? "var(--fg-3)" : "var(--fg-1)", fontStyle: r.status === "draft" ? "italic" : "normal", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.subject}</td>
                    <td style={td()}>
                      <span className={`badge ${STATUS_CLASS[r.status]} style-${badgeStyle}`}>
                        <span className="badge-dot" />{STATUS_LABEL[r.status]}
                      </span>
                    </td>
                    <td style={{ ...td("right"), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11 }}>{r.sent}</td>
                    <td style={{ ...td("right"), color: "var(--fg-2)", fontFamily: "var(--font-mono)", fontSize: 11 }}>
                      <span style={{ color: r.opens > 0 ? "var(--purple)" : "var(--fg-3)" }}>{r.opens}</span>
                      <span style={{ color: "var(--fg-3)" }}> · </span>
                      <span style={{ color: r.replies > 0 ? "var(--teal)" : "var(--fg-3)" }}>{r.replies}</span>
                    </td>
                    <td style={td()}>
                      <button className="btn btn-icon btn-sm btn-ghost" onClick={(e) => e.stopPropagation()}><Icon name="settings" size={11} /></button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          <div style={{ padding: "12px 16px", color: "var(--fg-3)", fontSize: 11.5, borderTop: "0.5px solid var(--border)", display: "flex", alignItems: "center", gap: 12 }}>
            <span>Showing {filtered.length} of {ROWS.length}</span>
            <span>·</span>
            <span>Last sync 2 min ago</span>
            <div style={{ flex: 1 }} />
            <span style={{ fontFamily: "var(--font-mono)" }}>↑↓ navigate · ⏎ open · ⌘A select all</span>
          </div>
        </div>
      </div>

      {drawer && <Drawer row={drawer} onClose={() => setDrawer(null)} />}
      {showSend && <SendModal count={selected.size > 0 ? selected.size : ROWS.filter((r) => r.status === "ready").length} onClose={() => setShowSend(false)} />}
    </div>
  );
}

