"use client";

import React from "react";
import { useParams, useRouter } from "next/navigation";
import { Icon } from "@/components/ui/Icon";
import { Sidebar } from "@/components/layout/Sidebar";
import { Topbar } from "@/components/layout/Topbar";

interface WizardData {
  intent: string;
  body: string;
  companies: string;
  regions: string[];
  titles: string[];
  companySize: string;
  industry: string;
  valueProp: string;
  sender: string;
  linkedin: string;
  emailSource: string;
  scrapingAck: boolean;
  llm: string;
}

const Field = ({ label, hint, children, optional }: { label: string; hint?: string; children: React.ReactNode; optional?: boolean }) => (
  <div style={{ marginBottom: 18 }}>
    <div className="label" style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
      <span>{label}</span>
      {optional && <span style={{ fontSize: 10.5, color: "var(--fg-3)", fontWeight: 400 }}>Optional</span>}
    </div>
    {children}
    {hint && <div className="hint">{hint}</div>}
  </div>
);

const Chip = ({ label, removable, onRemove }: { label: string; removable?: boolean; onRemove?: () => void }) => (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 4, padding: "3px 6px 3px 8px", background: "var(--bg-2)", border: "0.5px solid var(--border-strong)", borderRadius: 4, fontSize: 11.5, color: "var(--fg-1)" }}>
    {label}
    {removable && <button onClick={onRemove} style={{ background: "transparent", border: 0, color: "var(--fg-3)", cursor: "pointer", padding: 0, display: "grid", placeItems: "center" }}><Icon name="x" size={10} /></button>}
  </span>
);

const StepIntent = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "What are you pitching?" : "What roles are you looking for?"} hint="A sentence or two. We'll use this to personalize each email.">
      <textarea className="field" rows={3} value={data.intent} onChange={(e) => set("intent", e.target.value)} />
    </Field>
    {isB2B && (
      <Field label="One-line value proposition" hint="Used in subject lines and openers.">
        <input className="field" value={data.valueProp} onChange={(e) => set("valueProp", e.target.value)} />
      </Field>
    )}
    <Field label="Email body template" hint="Use {{firstName}}, {{company}}, {{role}} as variables. AI will personalize each line.">
      <textarea className="field" rows={7} value={data.body} onChange={(e) => set("body", e.target.value)} style={{ fontFamily: "var(--font-mono)", fontSize: 12.5 }} />
    </Field>
    <div style={{ display: "flex", gap: 8, alignItems: "center", padding: 10, background: "var(--bg-1)", border: "0.5px solid var(--border)", borderRadius: 8 }}>
      <Icon name="sparkles" size={13} style={{ color: "var(--accent)" }} />
      <span style={{ fontSize: 12, color: "var(--fg-1)" }}>Want help writing? </span>
      <button className="btn btn-sm" style={{ marginLeft: "auto" }}>Generate template</button>
    </div>
  </>
);

const StepTarget = ({ data, set, isB2B }: { data: WizardData; set: (k: keyof WizardData, v: unknown) => void; isB2B: boolean }) => (
  <>
    <Field label={isB2B ? "Target companies" : "Dream companies"} hint="Comma-separated. We'll also expand to similar companies if you'd like.">
      <textarea className="field" rows={3} value={data.companies} onChange={(e) => set("companies", e.target.value)} />
    </Field>
    {isB2B && (
      <>
        <Field label="Decision-maker titles">
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, padding: 8, background: "var(--bg-1)", border: "0.5px solid var(--border-strong)", borderRadius: 7, minHeight: 38 }}>
            {data.titles.map((t) => (
              <Chip key={t} label={t} removable onRemove={() => set("titles", (data.titles as string[]).filter((x) => x !== t))} />
            ))}
            <input placeholder="Add title…" style={{ flex: 1, minWidth: 100, background: "transparent", border: 0, color: "var(--fg)", fontSize: 12, padding: "2px 4px", outline: "none" }} />
          </div>
        </Field>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Field label="Industry">

