"use client";

import React from "react";
import { useRouter, useSearchParams } from "next/navigation";

export default function AuthCallbackPage() {
  const router = useRouter();
  const params = useSearchParams();
  const [error, setError] = React.useState("");

  React.useEffect(() => {
    const access_token = params.get("access_token");
    const refresh_token = params.get("refresh_token");
    const email = params.get("email");

    if (!access_token) {
      setError("Authentication failed. No token received.");
      return;
    }

    localStorage.setItem("outreach_token", access_token);
    if (refresh_token) localStorage.setItem("outreach_refresh_token", refresh_token);
    if (email) localStorage.setItem("outreach_email", email);

    router.replace("/dashboard");
  }, [params, router]);

  if (error) {
    return (
      <div style={{ height: "100%", display: "grid", placeItems: "center", color: "var(--fg)" }}>
        <div style={{ textAlign: "center" }}>
          <p style={{ color: "var(--red)", marginBottom: 16 }}>{error}</p>
          <a href="/auth" style={{ color: "var(--accent)" }}>Back to sign in</a>
        </div>
      </div>
    );
  }

  return (
    <div style={{ height: "100%", display: "grid", placeItems: "center", color: "var(--fg-2)", fontSize: 13 }}>
      <div style={{ textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>
        <span className="spinner" />
        Signing you in…
      </div>
    </div>
  );
}

