                      <span style={{ fontSize: 11.5, color: "var(--fg-2)", background: "var(--bg-3)", padding: "2px 7px", borderRadius: 4, border: "0.5px solid var(--border)" }}>{c.type.replace(/_/g, " ")}</span>
